// ===== STATE =====
// Prioritas data: localStorage (jika ada) → embedded data (dari file yg di-share) → kosong
function _loadState(key, fallback) {
  // Prioritas: localStorage (data terbaru, termasuk hasil sync Firebase) → embedded → fallback
  // siswa/guru di-merge: localStorage sebagai sumber utama, embedded sebagai fallback awal
  if ((key === 'siswa' || key === 'guru') && PKBM_EMBEDDED_DATA && PKBM_EMBEDDED_DATA[key] && PKBM_EMBEDDED_DATA[key].length > 0) {
    // Merge: localStorage sebagai prioritas, embedded sebagai base awal
    const embedded = PKBM_EMBEDDED_DATA[key];
    try {
      const ls = localStorage.getItem('pkbm_' + key);
      if (ls) {
        const lsData = JSON.parse(ls);
        const embeddedIds = new Set(embedded.map(x => x.id));
        const extra = lsData.filter(x => !embeddedIds.has(x.id));
        return [...embedded, ...extra];
      }
    } catch(e) {}
    return embedded;
  }
  const ls = localStorage.getItem('pkbm_' + key);
  if (ls !== null) { try { return JSON.parse(ls); } catch(e) {} }
  if (PKBM_EMBEDDED_DATA && PKBM_EMBEDDED_DATA[key] !== undefined) return PKBM_EMBEDDED_DATA[key];
  return fallback;
}

// Data siswa & guru SELALU dari PKBM_EMBEDDED_DATA (embedded dalam file HTML)
// Tidak perlu disalin ke localStorage — supaya bisa diakses di semua browser/server tanpa import ulang
function _syncEmbeddedToLocal() {
  if (!PKBM_EMBEDDED_DATA) return;
  // Hanya sync data non-master ke localStorage (soal, ujian, nilai, dll)
  const syncKeys = ['soal','ujian','ujian_online','jawaban_ujian','mapel','nilai','activity','fitur_baru','fitur_respons','naik_kelas','flayer_files'];
  for (const key of syncKeys) {
    if (!localStorage.getItem('pkbm_' + key) && PKBM_EMBEDDED_DATA[key] !== undefined) {
      try { localStorage.setItem('pkbm_' + key, JSON.stringify(PKBM_EMBEDDED_DATA[key])); } catch(e) {}
    }
  }
  if (PKBM_EMBEDDED_DATA.admin_user && !localStorage.getItem('pkbm_admin_user')) {
    localStorage.setItem('pkbm_admin_user', PKBM_EMBEDDED_DATA.admin_user);
  }
  if (PKBM_EMBEDDED_DATA.admin_pass && !localStorage.getItem('pkbm_admin_pass')) {
    localStorage.setItem('pkbm_admin_pass', PKBM_EMBEDDED_DATA.admin_pass);
  }
}

_syncEmbeddedToLocal();

let state = {
  siswa: _loadState('siswa', []),
  soal: _loadState('soal', []),
  ujian: _loadState('ujian', []),
  ujian_online: _loadState('ujian_online', []),
  jawaban_ujian: _loadState('jawaban_ujian', []),
  mapel: _loadState('mapel', []),
  nilai: _loadState('nilai', []),
  activity: _loadState('activity', []),
  guru: _loadState('guru', []),
  fitur_baru: _loadState('fitur_baru', []),
  fitur_respons: _loadState('fitur_respons', []),
  sumber_belajar: _loadState('sumber_belajar', []),
  perangkat_ajar: _loadState('perangkat_ajar', []),
  video_pembelajaran: _loadState('video_pembelajaran', []),
  naik_kelas: _loadState('naik_kelas', {}),
  flayer_files: _loadState('flayer_files', {}),
  kelas_program_ujian: _loadState('kelas_program_ujian', []),
  pengumuman: _loadState('pengumuman', []),
};

function save() {
  for (const key of ['siswa','soal','ujian','ujian_online','jawaban_ujian','mapel','nilai','activity','guru','fitur_baru','fitur_respons','sumber_belajar','perangkat_ajar','video_pembelajaran','naik_kelas','flayer_files','kelas_program_ujian','pengumuman']) {
    try {
      localStorage.setItem('pkbm_'+key, JSON.stringify(state[key]));
    } catch(e) {
      if(e.name==='QuotaExceededError'||e.code===22) {
        if(key==='sumber_belajar') {
          try {
            const lightData=state[key].map(sb=>({...sb, fileData: sb.fileData?'[FILE_TOO_LARGE_TO_CACHE]':'' }));
            localStorage.setItem('pkbm_'+key, JSON.stringify(lightData));
            showNotif('⚠️ Penyimpanan penuh! Beberapa file mungkin tidak tersimpan. Hapus materi lama.','var(--warning)');
          } catch(e2) { console.warn('Cannot save sumber_belajar:', e2); }
        } else {
          console.warn('QuotaExceeded for key:', key);
        }
      }
    }

    // ── Push ke Firebase (real-time sync) — semua key termasuk siswa/guru ──
    if (typeof SYNC_KEYS !== 'undefined' && SYNC_KEYS.includes(key)) {
      _pushToFirebase(key, state[key]);
    }
  }

  // Sync admin config juga
  const adminUser = localStorage.getItem('pkbm_admin_user');
  const adminPass = localStorage.getItem('pkbm_admin_pass');
  if (adminUser && typeof _pushToFirebase === 'function') {
    _pushToFirebase('admin_config', { admin_user: adminUser, admin_pass: adminPass });
  }

  // Update indikator sync
  if (typeof _renderSyncIndicator === 'function' && _fbOnline) {
    _renderSyncIndicator('syncing');
    setTimeout(() => _renderSyncIndicator('online'), 1200);
  }
}

function addActivity(text) {
  state.activity.unshift({ text, time: new Date().toLocaleString('id-ID') });
  if (state.activity.length > 20) state.activity.pop();
  save();
}

// ===== NAVIGATION =====
function showPage(id) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.getElementById('page-'+id).classList.add('active');
  document.querySelectorAll('.nav-item').forEach(n => {
    if (n.getAttribute('onclick') && n.getAttribute('onclick').includes("'"+id+"'")) n.classList.add('active');
  });
  if (id === 'dashboard') updateDashboard();
  if (id === 'laporan') updateLaporan();
  if (id === 'rapor') updateRaporSelect();
  if (id === 'guru') { renderGuru(); populateGuruMapelSelect(); }
  if (id === 'akun') { renderAkunGuru(); populateAkunKelasFilter(); }
  if (id === 'fitur-baru') { renderFiturBaru(); }
  // Auto-close sidebar on mobile after nav click
  if (window.innerWidth <= 768) closeSidebar();
}

/* ─── Mobile Sidebar Toggle ─── */
function toggleSidebar() {
  const sb = document.getElementById('main-sidebar');
  const bd = document.getElementById('sidebar-backdrop');
  if (!sb) return;
  const isOpen = sb.classList.contains('open');
  if (isOpen) { closeSidebar(); } else { openSidebar(); }
}
function openSidebar() {
  const sb = document.getElementById('main-sidebar');
  const bd = document.getElementById('sidebar-backdrop');
  if (sb) sb.classList.add('open');
  if (bd) bd.classList.add('show');
  document.body.style.overflow = 'hidden';
}
function closeSidebar() {
  const sb = document.getElementById('main-sidebar');
  const bd = document.getElementById('sidebar-backdrop');
  if (sb) sb.classList.remove('open');
  if (bd) bd.classList.remove('show');
  document.body.style.overflow = '';
}
// Close sidebar on ESC key
document.addEventListener('keydown', function(e) { if (e.key === 'Escape') closeSidebar(); });
// Close sidebar on resize to desktop
window.addEventListener('resize', function() { if (window.innerWidth > 768) closeSidebar(); });

// ===== MODAL =====
function openModal(id) {
  if (id === 'modal-buat-fitur') {
    const editId = document.getElementById('fb-edit-id');
    if (editId && !editId.value) {
      // Reset form for new fitur
      document.getElementById('fb-jenis').value = 'pengumuman';
      document.getElementById('fb-ikon').value = '📢';
      document.getElementById('fb-judul').value = '';
      document.getElementById('fb-deskripsi').value = '';
      document.getElementById('fb-target-guru').checked = true;
      document.getElementById('fb-target-siswa').checked = true;
      document.getElementById('fb-status').value = 'aktif';
      document.getElementById('fb-tgl-mulai').value = '';
      document.getElementById('fb-tgl-akhir').value = '';
      document.getElementById('fb-prioritas').value = 'normal';
      renderFiturExtraFields('pengumuman');
    }
  }
  document.getElementById(id).classList.add('show');
}
function closeModal(id) { document.getElementById(id).classList.remove('show'); }
window.addEventListener('click', e => {
  if (e.target.classList.contains('modal-overlay')) e.target.classList.remove('show');
});

// ===== NOTIFICATION =====
function showNotif(msg, color='var(--success)') {
  const n = document.getElementById('notif-toast');
  const t = document.getElementById('notif-text');
  t.textContent = msg;
  n.style.borderLeftColor = color;
  n.classList.add('show');
  setTimeout(() => n.classList.remove('show'), 3500);
}

// ===== TABS =====
function switchTab(containerId, activeId) {
  const container = document.getElementById(containerId);
  container.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('active'));
  document.getElementById(activeId).classList.add('active');
  const tabs = document.querySelectorAll('.tabs .tab');
  const panes = container.querySelectorAll('.tab-pane');
  tabs.forEach((t,i) => { if (panes[i] && panes[i].id === activeId) t.classList.add('active'); else t.classList.remove('active'); });
}

// ===== MAPEL HELPERS =====
function getMapelOptions() {
  const defaultMapel = [
    // Umum / Paket
    'Matematika','Bahasa Indonesia','Bahasa Inggris','IPA','IPS','PKn','Agama','Prakarya','Seni Budaya','PJOK',
    // SMA Program IPS
    'Matematika Wajib','Matematika Peminatan',
    'Bahasa Indonesia Wajib','Bahasa Inggris Wajib',
    'Ekonomi','Sosiologi','Geografi','Sejarah',
    'Sejarah Indonesia','Sejarah Peminatan',
    'Pendidikan Agama','PPKn',
    'Seni Budaya SMA','PJOK SMA',
    'Prakarya & Kewirausahaan','Lintas Minat Biologi','Lintas Minat Fisika',
    'Bahasa Jepang','Bahasa Arab','Bahasa Jerman','Bahasa Perancis',
    // BK
    'Bimbingan Konseling'
  ];
  const custom = state.mapel.map(m => m.nama);
  return [...new Set([...defaultMapel, ...custom])];
}
function populateMapelSelects() {
  const opts = getMapelOptions();
  ['q-mapel','u-mapel','nilai-mapel','filter-mapel-soal'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    const val = el.value;
    const first = el.options[0];
    el.innerHTML = '';
    el.appendChild(first);
    opts.forEach(m => { const o = new Option(m,m); el.appendChild(o); });
    el.value = val;
  });
}

// ===== DASHBOARD =====
function updateDashboard() {
  document.getElementById('stat-total-siswa').textContent = state.siswa.length;
  document.getElementById('stat-total-ujian').textContent = state.ujian.length;
  document.getElementById('stat-total-soal').textContent = state.soal.length;
  document.getElementById('badge-siswa').textContent = state.siswa.length;
  const visibleSoalCount = currentUser && currentUser.role === 'guru' 
    ? state.soal.filter(s => s.guruId === currentUser.data.id || !s.guruId).length 
    : state.soal.length;
  document.getElementById('badge-soal').textContent = visibleSoalCount;

  // avg nilai
  if (state.nilai.length > 0) {
    const avg = state.nilai.reduce((s,n) => s + (parseFloat(n.akhir)||0), 0) / state.nilai.length;
    document.getElementById('stat-avg-nilai').textContent = avg.toFixed(1);
  }

  // activity
  const act = document.getElementById('activity-list');
  if (state.activity.length === 0) {
    act.innerHTML = '<div class="empty-state" style="padding:20px 0;"><p>Belum ada aktivitas</p></div>';
  } else {
    act.innerHTML = state.activity.slice(0,8).map(a => `
      <div style="padding:10px 0;border-bottom:1px solid var(--border);font-size:13px;">
        <div>${a.text}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${a.time}</div>
      </div>`).join('');
  }

  // chart mapel
  const byMapel = {};
  state.nilai.forEach(n => {
    if (!byMapel[n.mapel]) byMapel[n.mapel] = [];
    byMapel[n.mapel].push(parseFloat(n.akhir)||0);
  });
  const chartEl = document.getElementById('chart-mapel');
  if (Object.keys(byMapel).length === 0) {
    chartEl.innerHTML = '<div class="empty-state" style="padding:20px 0;"><div style="font-size:36px;">📊</div><p>Tambahkan nilai untuk melihat statistik</p></div>';
  } else {
    chartEl.innerHTML = Object.entries(byMapel).map(([m,vals]) => {
      const avg = vals.reduce((s,v) => s+v,0)/vals.length;
      const pct = Math.min(avg,100);
      const color = avg>=75?'var(--success)':avg>=60?'var(--warning)':'var(--danger)';
      return `<div style="margin-bottom:14px;">
        <div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:5px;">
          <span style="font-weight:600;">${m}</span>
          <span style="font-weight:700;color:${color};">${avg.toFixed(1)}</span>
        </div>
        <div class="progress-bar"><div class="progress-fill" style="width:${pct}%;background:${color};"></div></div>
      </div>`;
    }).join('');
  }
}

// ===== SISWA =====
function tambahSiswa() {
  const nisn = document.getElementById('s-nisn').value.trim();
  const nama = document.getElementById('s-nama').value.trim();
  if (!nisn || !nama) { showNotif('⚠️ NISN dan Nama wajib diisi!','var(--warning)'); return; }
  const siswa = {
    id: Date.now(), nisn, nis: document.getElementById('s-nis').value,
    nama, jk: document.getElementById('s-jk').value, ttl: document.getElementById('s-ttl').value,
    kelas: document.getElementById('s-kelas').value, tahun: document.getElementById('s-tahun').value,
    hp: document.getElementById('s-hp').value, status: document.getElementById('s-status').value,
    alamat: document.getElementById('s-alamat').value
  };
  state.siswa.push(siswa);
  save();
  renderSiswa();
  updateMapelDropdowns();
  closeModal('modal-siswa');
  showNotif(`✅ Siswa "${nama}" berhasil ditambahkan!`);
  addActivity(`Siswa baru ditambahkan: ${nama} (${siswa.kelas})`);
  ['s-nisn','s-nis','s-nama','s-ttl','s-tahun','s-hp','s-alamat'].forEach(id => document.getElementById(id).value = '');
}

function renderSiswa(list) {
  const data = list || state.siswa;
  const tbody = document.getElementById('tbody-siswa');
  if (data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;padding:40px;color:var(--text-muted);"><div style="font-size:36px;margin-bottom:8px;">👨‍🎓</div>Belum ada data siswa</td></tr>';
    return;
  }
  tbody.innerHTML = data.map((s,i) => {
    const ttlFormatted = s.ttl ? new Date(s.ttl+'T00:00:00').toLocaleDateString('id-ID',{day:'2-digit',month:'2-digit',year:'numeric'}) : '<span style="color:#ef4444;font-size:11px;">Belum diisi</span>';
    return `<tr>
      <td>${i+1}</td>
      <td><code style="font-size:12px;background:#f1f5f9;padding:2px 6px;border-radius:4px;">${s.nisn||'-'}</code></td>
      <td><strong>${s.nama}</strong></td>
      <td><span class="tag">${s.kelas||'-'}</span></td>
      <td style="font-size:12.5px;">${ttlFormatted}</td>
      <td>${s.jk === 'Laki-laki' ? '🧑' : '👩'} ${s.jk||'-'}</td>
      <td style="font-size:12.5px;">${s.hp || '-'}</td>
      <td><span class="badge ${s.status==='Aktif'?'badge-success':s.status==='Lulus'?'badge-primary':'badge-gray'}">${s.status||'-'}</span></td>
      <td style="white-space:nowrap;">
        <button class="btn btn-sm btn-outline" onclick="showDetailSiswa(${s.id})" style="padding:4px 8px;font-size:11px;">👁️</button>
        <button class="btn btn-sm btn-primary" onclick="showAkunIndividu('siswa',${s.id})" style="padding:4px 8px;font-size:11px;">🔐</button>
        <button class="btn btn-sm" onclick="hapusSiswa(${s.id})" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️</button>
      </td>
    </tr>`;
  }).join('');
  document.getElementById('badge-siswa').textContent = state.siswa.length;
}

function filterSiswa() {
  const q = document.getElementById('search-siswa').value.toLowerCase();
  const kelas = document.getElementById('filter-kelas-siswa').value;
  const filtered = state.siswa.filter(s =>
    (s.nama.toLowerCase().includes(q) || s.nisn.includes(q)) &&
    (!kelas || s.kelas === kelas)
  );
  renderSiswa(filtered);
}

function hapusSiswa(id) {
  if (!confirm('Yakin hapus siswa ini?')) return;
  const s = state.siswa.find(x => x.id === id);
  state.siswa = state.siswa.filter(x => x.id !== id);
  save();
  renderSiswa();
  showNotif(`🗑️ Siswa berhasil dihapus!`, 'var(--danger)');
  if (s) addActivity(`Siswa dihapus: ${s.nama}`);
}

function showDetailSiswa(id) {
  const s = state.siswa.find(x => x.id === id);
  if (!s) return;
  const nilaiSiswa = state.nilai.filter(n => n.siswaId === id);
  document.getElementById('detail-siswa-body').innerHTML = `
    <div style="display:flex;gap:20px;margin-bottom:20px;align-items:center;">
      <div style="width:72px;height:72px;border-radius:50%;background:var(--primary);display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:800;color:#fff;flex-shrink:0;">${s.nama[0]}</div>
      <div>
        <h3 style="font-size:18px;font-weight:800;">${s.nama}</h3>
        <p style="color:var(--text-muted);font-size:13px;">NISN: ${s.nisn} &bull; ${s.kelas}</p>
        <span class="badge ${s.status==='Aktif'?'badge-success':'badge-gray'}" style="margin-top:4px;">${s.status}</span>
      </div>
    </div>
    <div class="form-row">
      <div><strong>Jenis Kelamin:</strong> ${s.jk}</div>
      <div><strong>Tgl Lahir:</strong> ${s.ttl || '-'}</div>
      <div><strong>Tahun Masuk:</strong> ${s.tahun || '-'}</div>
      <div><strong>No HP/Ortu:</strong> ${s.hp || '-'}</div>
    </div>
    <div style="margin-top:12px;"><strong>Alamat:</strong> ${s.alamat || '-'}</div>
    <hr class="divider">
    <h4 style="font-size:14px;font-weight:700;margin-bottom:12px;">📊 Riwayat Nilai</h4>
    ${nilaiSiswa.length === 0 ? '<p style="color:var(--text-muted);">Belum ada nilai</p>' :
      nilaiSiswa.map(n => `
        <div style="display:flex;justify-content:space-between;padding:10px;background:#f8fafc;border-radius:8px;margin-bottom:8px;font-size:13px;">
          <span><strong>${n.mapel}</strong> - ${n.jenis}</span>
          <div>
            <span class="score-circle" style="width:44px;height:44px;font-size:15px;border-color:${parseFloat(n.akhir)>=70?'var(--success)':'var(--danger)'};">${n.akhir}</span>
          </div>
        </div>`).join('')}
  `;
  openModal('modal-detail-siswa');
}

// ===== SOAL =====
function tambahSoal() {
  const mapel = document.getElementById('q-mapel').value;
  const pertanyaan = document.getElementById('q-pertanyaan').value.trim();
  const tipe = document.getElementById('q-tipe').value;
  if (!mapel || !pertanyaan) { showNotif('⚠️ Mapel dan soal wajib diisi!','var(--warning)'); return; }

  let kunci = '';
  if (tipe === 'Pilihan Ganda') {
    const checked = document.querySelector('input[name="correct"]:checked');
    kunci = checked ? checked.value : '';
  }

  const soal = {
    id: Date.now(), mapel, tipe,
    level: document.getElementById('q-level').value,
    poin: document.getElementById('q-poin').value,
    pertanyaan,
    opsiA: document.getElementById('opt-A')?.value || '',
    opsiB: document.getElementById('opt-B')?.value || '',
    opsiC: document.getElementById('opt-C')?.value || '',
    opsiD: document.getElementById('opt-D')?.value || '',
    kunci,
    pembahasan: document.getElementById('q-pembahasan').value,
    guruId: (currentUser && currentUser.role === 'guru') ? currentUser.data.id : null,
    guruNama: (currentUser && currentUser.role === 'guru') ? currentUser.data.nama : 'Admin'
  };
  state.soal.push(soal);
  save();
  renderSoal();
  closeModal('modal-soal');
  showNotif(`✅ Soal berhasil ditambahkan ke bank soal!`);
  addActivity(`Soal baru: "${pertanyaan.slice(0,40)}..." (${mapel})`);
  document.getElementById('badge-soal').textContent = state.soal.length;
}

function getSoalVisible() {
  // Admin: all soal
  // Guru: only soal created by this guru (guruId === guru.id) or soal with no guruId (created before this feature)
  // Siswa: all soal (for exam purposes, filtered by exam)
  if (!currentUser || currentUser.role === 'admin') return state.soal;
  if (currentUser.role === 'guru') {
    const gId = currentUser.data.id;
    return state.soal.filter(s => s.guruId === gId || s.guruId === null || s.guruId === undefined);
  }
  return state.soal; // siswa sees filtered soal in exam context
}

function renderSoal(list) {
  const data = list || getSoalVisible();
  const tbody = document.getElementById('tbody-soal');
  const levelColor = { Mudah:'badge-success', Sedang:'badge-warning', Sulit:'badge-danger' };
  if (data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:40px;color:var(--text-muted);"><div style="font-size:36px;">📝</div>Belum ada soal</td></tr>';
    return;
  }
  tbody.innerHTML = data.map((s,i) => `
    <tr>
      <td>${i+1}</td>
      <td style="max-width:300px;"><span style="font-size:13px;">${s.pertanyaan.slice(0,80)}${s.pertanyaan.length>80?'...':''}</span></td>
      <td><span class="tag">${s.mapel}</span></td>
      <td><span class="badge badge-primary">${s.tipe}</span></td>
      <td><span class="badge ${levelColor[s.level]||'badge-gray'}">${s.level}</span></td>
      <td><strong>${s.poin}</strong></td>
      <td>
        <button class="btn btn-sm" onclick="hapusSoal(${s.id})" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️</button>
      </td>
    </tr>`).join('');
}

function filterSoal() {
  const q = document.getElementById('search-soal').value.toLowerCase();
  const mapel = document.getElementById('filter-mapel-soal').value;
  const tipe = document.getElementById('filter-tipe-soal').value;
  const visible = getSoalVisible();
  const filtered = visible.filter(s =>
    s.pertanyaan.toLowerCase().includes(q) &&
    (!mapel || s.mapel === mapel) &&
    (!tipe || s.tipe === tipe)
  );
  renderSoal(filtered);
}

function hapusSoal(id) {
  if (!confirm('Yakin hapus soal ini?')) return;
  state.soal = state.soal.filter(x => x.id !== id);
  save();
  renderSoal();
  showNotif('🗑️ Soal dihapus!','var(--danger)');
}

function updateAnswerForm() {
  const tipe = document.getElementById('q-tipe').value;
  const container = document.getElementById('answer-form');
  if (tipe === 'Pilihan Ganda') {
    container.style.display = '';
    document.getElementById('options-container').innerHTML = ['A','B','C','D'].map(op => `
      <div class="answer-option"><input type="radio" name="correct" value="${op}"><span style="width:26px;font-weight:700;color:var(--primary);">${op}</span><input type="text" class="form-control" id="opt-${op}" placeholder="Pilihan ${op}" style="margin:0;"></div>
    `).join('');
  } else if (tipe === 'Benar/Salah') {
    container.style.display = '';
    document.getElementById('options-container').innerHTML = `
      <div class="answer-option"><input type="radio" name="correct" value="Benar"><span style="font-weight:700;">✅ Benar</span></div>
      <div class="answer-option"><input type="radio" name="correct" value="Salah"><span style="font-weight:700;">❌ Salah</span></div>`;
  } else {
    container.style.display = '';
    document.getElementById('options-container').innerHTML = `
      <div class="form-group"><label class="form-label">Kunci Jawaban</label><input type="text" class="form-control" id="opt-A" placeholder="Tulis kunci jawaban..."></div>`;
  }
}

// ===== UJIAN =====
function tambahUjian() {
  const nama = document.getElementById('u-nama').value.trim();
  const mapel = document.getElementById('u-mapel').value;
  if (!nama || !mapel) { showNotif('⚠️ Nama ujian dan mapel wajib diisi!','var(--warning)'); return; }
  const ujian = {
    id: Date.now(), nama, mapel,
    kelas: document.getElementById('u-kelas').value,
    mulai: document.getElementById('u-mulai').value,
    selesai: document.getElementById('u-selesai').value,
    durasi: document.getElementById('u-durasi').value,
    jenis: document.getElementById('u-jenis').value,
    jumlahSoal: document.getElementById('u-jumlah-soal').value,
    kkm: document.getElementById('u-kkm').value,
    keterangan: document.getElementById('u-ket').value,
    status: 'Terjadwal', tanggalBuat: new Date().toLocaleDateString('id-ID')
  };
  state.ujian.push(ujian);
  save();
  renderUjian();
  closeModal('modal-ujian');
  showNotif(`✅ Ujian "${nama}" berhasil dibuat!`);
  addActivity(`Ujian dibuat: ${nama} (${mapel})`);
  document.getElementById('stat-total-ujian').textContent = state.ujian.length;
}

function renderUjian() {
  const cont = document.getElementById('list-ujian');
  if (state.ujian.length === 0) {
    cont.innerHTML = '<div class="empty-state"><div class="empty-icon">📋</div><h4>Belum ada ujian</h4><p>Klik "Buat Ujian Baru" untuk membuat ujian pertama</p></div>';
    return;
  }
  const statusColor = { Terjadwal:'badge-primary', Berlangsung:'badge-success', Selesai:'badge-gray' };
  cont.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:16px;">` +
    state.ujian.map(u => `
    <div class="card" style="border-left:4px solid var(--primary);">
      <div class="card-body">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px;">
          <div>
            <h4 style="font-size:15px;font-weight:800;">${u.nama}</h4>
            <p style="font-size:12px;color:var(--text-muted);">${u.mapel} &bull; ${u.kelas}</p>
          </div>
          <span class="badge ${statusColor[u.status]||'badge-gray'}">${u.status}</span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:12.5px;margin-bottom:12px;">
          <div><span style="color:var(--text-muted);">Jenis:</span> <strong>${u.jenis}</strong></div>
          <div><span style="color:var(--text-muted);">Durasi:</span> <strong>${u.durasi} menit</strong></div>
          <div><span style="color:var(--text-muted);">Soal:</span> <strong>${u.jumlahSoal} butir</strong></div>
          <div><span style="color:var(--text-muted);">KKM:</span> <strong>${u.kkm}</strong></div>
        </div>
        ${u.mulai ? `<div style="font-size:12px;color:var(--text-muted);margin-bottom:12px;">📅 ${new Date(u.mulai).toLocaleString('id-ID')}</div>` : ''}
        <div style="display:flex;gap:6px;">
          <button class="btn btn-sm btn-primary" onclick="mulaiUjian(${u.id})">▶️ Mulai</button>
          <button class="btn btn-sm btn-outline" onclick="showNotif('📋 Fitur duplikasi akan segera hadir!')">📋 Duplikat</button>
          <button class="btn btn-sm" onclick="hapusUjian(${u.id})" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️</button>
        </div>
      </div>
    </div>`).join('') + '</div>';
}

function mulaiUjian(id) {
  const u = state.ujian.find(x => x.id === id);
  if (!u) return;
  u.status = 'Berlangsung';
  save();
  renderUjian();
  showNotif(`▶️ Ujian "${u.nama}" dimulai!`);
  addActivity(`Ujian dimulai: ${u.nama}`);
}

function hapusUjian(id) {
  if (!confirm('Yakin hapus ujian ini?')) return;
  state.ujian = state.ujian.filter(x => x.id !== id);
  save();
  renderUjian();
  showNotif('🗑️ Ujian dihapus!','var(--danger)');
}

// ===== MAPEL =====
function getSelectedKelas() {
  const checked = [...document.querySelectorAll('.mk-check:not(#mk-semua):checked')];
  return checked.map(c => c.value);
}

function updateMkPreview() {
  const selected = getSelectedKelas();
  const semaKelas = document.getElementById('mk-semua');
  const previewText = document.getElementById('mk-preview-text');
  if (!previewText) return;
  if (semaKelas && semaKelas.checked) {
    previewText.innerHTML = '<strong style="color:var(--primary);">✅ Semua Kelas / Program dipilih</strong>';
    return;
  }
  if (selected.length === 0) {
    previewText.textContent = 'Belum ada kelas dipilih';
    previewText.style.color = 'var(--text-muted)';
    return;
  }
  previewText.style.color = 'var(--primary)';
  previewText.innerHTML = `<strong>${selected.length} kelas dipilih:</strong> ` +
    selected.map(k => `<span style="background:#eff6ff;color:var(--primary);padding:2px 7px;border-radius:5px;font-size:11.5px;margin:2px 2px 2px 0;display:inline-block;">${k}</span>`).join('');
}

function mapelToggleSemua(el) {
  const isChecked = el.checked;
  document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => { c.checked = false; c.disabled = isChecked; });
  updateMkPreview();
}

function mapelPilihSemua() {
  document.getElementById('mk-semua').checked = true;
  document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => { c.checked = false; c.disabled = true; });
  updateMkPreview();
}

function mapelHapusSemua() {
  document.querySelectorAll('.mk-check').forEach(c => { c.checked = false; c.disabled = false; });
  updateMkPreview();
}

function mapelPilihIPS() {
  document.getElementById('mk-semua').checked = false;
  document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => c.disabled = false);
  document.querySelectorAll('.mk-ips').forEach(c => c.checked = true);
  updateMkPreview();
}

function mapelPilihIPA() {
  document.getElementById('mk-semua').checked = false;
  document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => c.disabled = false);
  document.querySelectorAll('.mk-ipa').forEach(c => c.checked = true);
  updateMkPreview();
}

function mapelPilihPaket() {
  document.getElementById('mk-semua').checked = false;
  document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => c.disabled = false);
  document.querySelectorAll('.mk-paket').forEach(c => c.checked = true);
  updateMkPreview();
}

// Pasang event listener update preview saat checkbox diubah
document.addEventListener('change', function(e) {
  if (e.target.classList.contains('mk-check') && e.target.id !== 'mk-semua') {
    if (e.target.checked) {
      document.getElementById('mk-semua').checked = false;
      document.querySelectorAll('.mk-check:not(#mk-semua)').forEach(c => c.disabled = false);
    }
    updateMkPreview();
  }
});

function tambahMapel() {
  const kode = document.getElementById('m-kode').value.trim();
  const nama = document.getElementById('m-nama').value.trim();
  const kkm = document.getElementById('m-kkm').value;
  if (!kode || !nama) { showNotif('⚠️ Kode dan nama mapel wajib diisi!','var(--warning)'); return; }

  // Ambil kelas yang dipilih (multi)
  const semaKelas = document.getElementById('mk-semua');
  let kelasArr = [];
  if (semaKelas && semaKelas.checked) {
    kelasArr = ['Semua'];
  } else {
    kelasArr = getSelectedKelas();
    if (kelasArr.length === 0) kelasArr = ['Semua'];
  }

  const mapel = {
    id: Date.now(), kode, nama, kkm,
    kelas: kelasArr.join(', '),
    kelasArr: kelasArr,
    status: document.getElementById('m-status').value
  };
  state.mapel.push(mapel);
  save();
  renderMapel();
  populateMapelSelects();
  populateSoalImportMapel();
  closeModal('modal-mapel');
  showNotif(`✅ Mata pelajaran "${nama}" berhasil ditambahkan!`);
  ['m-kode','m-nama'].forEach(id => document.getElementById(id).value = '');
  // Reset checkboxes
  mapelHapusSemua();
}

function renderMapel() {
  const tbody = document.getElementById('tbody-mapel');
  if (state.mapel.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:30px;color:var(--text-muted);">Belum ada mata pelajaran</td></tr>';
    return;
  }
  tbody.innerHTML = state.mapel.map((m,i) => {
    // Support format lama (string) dan baru (array)
    const kelasList = m.kelasArr ? m.kelasArr : (m.kelas ? m.kelas.split(', ') : ['Semua']);
    const kelasBadges = kelasList.map(k =>
      `<span style="display:inline-block;background:#eff6ff;color:var(--primary);padding:1px 7px;border-radius:5px;font-size:11px;margin:2px 2px 2px 0;white-space:nowrap;">${k}</span>`
    ).join('');
    return `
    <tr>
      <td>${i+1}</td>
      <td><code style="background:#eff6ff;color:var(--primary);padding:2px 8px;border-radius:4px;font-size:12px;">${m.kode}</code></td>
      <td><strong>${m.nama}</strong></td>
      <td style="max-width:200px;">${kelasBadges}</td>
      <td><strong>${m.kkm}</strong></td>
      <td><span class="badge ${m.status==='Aktif'?'badge-success':'badge-gray'}">${m.status}</span></td>
      <td>
        <button class="btn btn-sm" onclick="hapusMapel(${m.id})" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️</button>
      </td>
    </tr>`;
  }).join('');
}

function hapusMapel(id) {
  if (!confirm('Yakin hapus mata pelajaran ini?')) return;
  state.mapel = state.mapel.filter(x => x.id !== id);
  save();
  renderMapel();
  showNotif('🗑️ Mata pelajaran dihapus!','var(--danger)');
}

// ===== NILAI =====
function loadNilaiTable() {
  const mapel = document.getElementById('nilai-mapel').value;
  const kelas = document.getElementById('nilai-kelas').value;
  const jenis = document.getElementById('nilai-jenis').value;
  if (!mapel || !kelas) { showNotif('⚠️ Pilih mapel dan kelas terlebih dahulu!','var(--warning)'); return; }
  const siswaTerkait = state.siswa.filter(s => !kelas || s.kelas === kelas);
  if (siswaTerkait.length === 0) { showNotif('⚠️ Tidak ada siswa di kelas tersebut!','var(--warning)'); return; }

  document.getElementById('nilai-table-title').textContent = `Nilai ${jenis} - ${mapel} - ${kelas}`;
  const tbody = document.getElementById('tbody-nilai');
  tbody.innerHTML = siswaTerkait.map((s,i) => {
    const existing = state.nilai.find(n => n.siswaId===s.id && n.mapel===mapel && n.jenis===jenis) || {};
    return `<tr>
      <td>${i+1}</td>
      <td><strong>${s.nama}</strong></td>
      <td><code style="font-size:11px;">${s.nisn}</code></td>
      <td><input type="number" class="form-control" style="width:80px;padding:4px 8px;" data-id="${s.id}" data-field="tugas" min="0" max="100" value="${existing.tugas||''}" oninput="hitungNilai(${s.id})"></td>
      <td><input type="number" class="form-control" style="width:80px;padding:4px 8px;" data-id="${s.id}" data-field="uh" min="0" max="100" value="${existing.uh||''}" oninput="hitungNilai(${s.id})"></td>
      <td><input type="number" class="form-control" style="width:80px;padding:4px 8px;" data-id="${s.id}" data-field="uts" min="0" max="100" value="${existing.uts||''}" oninput="hitungNilai(${s.id})"></td>
      <td><input type="number" class="form-control" style="width:80px;padding:4px 8px;" data-id="${s.id}" data-field="uas" min="0" max="100" value="${existing.uas||''}" oninput="hitungNilai(${s.id})"></td>
      <td><input type="number" class="form-control" style="width:80px;padding:4px 8px;font-weight:700;" data-id="${s.id}" data-field="akhir" id="akhir-${s.id}" min="0" max="100" value="${existing.akhir||''}"></td>
      <td id="predikat-${s.id}">${getPredikat(existing.akhir)}</td>
      <td><input type="text" class="form-control" style="width:120px;padding:4px 8px;" data-id="${s.id}" data-field="ket" value="${existing.ket||''}" placeholder="Keterangan"></td>
    </tr>`;
  }).join('');
  document.getElementById('nilai-table-card').style.display = '';
}

function hitungNilai(siswaId) {
  const t = parseFloat(document.querySelector(`[data-id="${siswaId}"][data-field="tugas"]`)?.value)||0;
  const uh = parseFloat(document.querySelector(`[data-id="${siswaId}"][data-field="uh"]`)?.value)||0;
  const uts = parseFloat(document.querySelector(`[data-id="${siswaId}"][data-field="uts"]`)?.value)||0;
  const uas = parseFloat(document.querySelector(`[data-id="${siswaId}"][data-field="uas"]`)?.value)||0;
  const count = [t,uh,uts,uas].filter(v=>v>0).length;
  const akhir = count > 0 ? ((t+uh+uts+uas)/count).toFixed(1) : '';
  const el = document.getElementById(`akhir-${siswaId}`);
  if (el) el.value = akhir;
  const pred = document.getElementById(`predikat-${siswaId}`);
  if (pred) pred.innerHTML = getPredikat(akhir);
}

function getPredikat(nilai) {
  const n = parseFloat(nilai);
  if (!n) return '<span class="badge badge-gray">-</span>';
  if (n >= 90) return '<span class="badge badge-success">A (Sangat Baik)</span>';
  if (n >= 80) return '<span class="badge badge-primary">B (Baik)</span>';
  if (n >= 70) return '<span class="badge badge-warning">C (Cukup)</span>';
  return '<span class="badge badge-danger">D (Kurang)</span>';
}

function saveNilai() {
  const mapel = document.getElementById('nilai-mapel').value;
  const kelas = document.getElementById('nilai-kelas').value;
  const jenis = document.getElementById('nilai-jenis').value;
  const rows = document.querySelectorAll('#tbody-nilai tr');
  let saved = 0;
  rows.forEach(row => {
    const siswaId = parseInt(row.querySelector('[data-id]')?.getAttribute('data-id'));
    if (!siswaId) return;
    const akhir = row.querySelector(`[data-id="${siswaId}"][data-field="akhir"]`)?.value;
    const existing = state.nilai.findIndex(n => n.siswaId===siswaId && n.mapel===mapel && n.jenis===jenis);
    const nilaiObj = {
      siswaId, mapel, kelas, jenis,
      tugas: row.querySelector(`[data-id="${siswaId}"][data-field="tugas"]`)?.value || '',
      uh: row.querySelector(`[data-id="${siswaId}"][data-field="uh"]`)?.value || '',
      uts: row.querySelector(`[data-id="${siswaId}"][data-field="uts"]`)?.value || '',
      uas: row.querySelector(`[data-id="${siswaId}"][data-field="uas"]`)?.value || '',
      akhir: akhir || '',
      ket: row.querySelector(`[data-id="${siswaId}"][data-field="ket"]`)?.value || ''
    };
    if (existing >= 0) state.nilai[existing] = nilaiObj;
    else if (akhir) { state.nilai.push(nilaiObj); saved++; }
  });
  save();
  showNotif(`✅ Nilai berhasil disimpan!`);
  addActivity(`Nilai disimpan: ${jenis} - ${mapel} - ${kelas}`);
}

// ===== LAPORAN =====
function updateLaporan() {
  const allNilai = state.nilai.map(n => parseFloat(n.akhir)).filter(v => !isNaN(v));
  if (allNilai.length === 0) return;
  const max = Math.max(...allNilai);
  const avg = allNilai.reduce((a,b)=>a+b,0)/allNilai.length;
  const remedial = allNilai.filter(v=>v<70).length;
  document.getElementById('lap-tertinggi').textContent = max;
  document.getElementById('lap-rata').textContent = avg.toFixed(1);
  document.getElementById('lap-remedial').textContent = remedial;

  // distribusi
  const bands = { 'A (90-100)':0, 'B (80-89)':0, 'C (70-79)':0, 'D (<70)':0 };
  allNilai.forEach(v => {
    if (v>=90) bands['A (90-100)']++;
    else if (v>=80) bands['B (80-89)']++;
    else if (v>=70) bands['C (70-79)']++;
    else bands['D (<70)']++;
  });
  const colors = ['var(--success)','var(--primary)','var(--warning)','var(--danger)'];
  document.getElementById('distribusi-nilai').innerHTML = Object.entries(bands).map(([k,v],i) => `
    <div style="margin-bottom:12px;">
      <div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:4px;">
        <span>${k}</span><span style="font-weight:700;">${v} siswa</span>
      </div>
      <div class="progress-bar"><div class="progress-fill" style="width:${allNilai.length>0?(v/allNilai.length*100):0}%;background:${colors[i]};"></div></div>
    </div>`).join('');

  // capaian mapel
  const byMapel = {};
  state.nilai.forEach(n => {
    if (!byMapel[n.mapel]) byMapel[n.mapel] = [];
    const v = parseFloat(n.akhir);
    if (!isNaN(v)) byMapel[n.mapel].push(v);
  });
  document.getElementById('capaian-mapel').innerHTML = Object.entries(byMapel).map(([m,vals]) => {
    const a = vals.reduce((s,v)=>s+v,0)/vals.length;
    return `<div style="display:flex;justify-content:space-between;padding:10px;background:#f8fafc;border-radius:8px;margin-bottom:8px;font-size:13px;">
      <span style="font-weight:600;">${m}</span>
      <span style="font-weight:700;color:${a>=70?'var(--success)':'var(--danger)'};">${a.toFixed(1)}</span>
    </div>`;
  }).join('') || '<div class="empty-state" style="padding:20px 0;"><p>Belum ada data</p></div>';

  // rekap
  const tbody = document.getElementById('tbody-rekap');
  const bySiswa = {};
  state.nilai.forEach(n => {
    if (!bySiswa[n.siswaId]) bySiswa[n.siswaId] = [];
    const v = parseFloat(n.akhir);
    if (!isNaN(v)) bySiswa[n.siswaId].push(v);
  });
  tbody.innerHTML = Object.entries(bySiswa).map(([id,vals],i) => {
    const siswa = state.siswa.find(s => s.id === parseInt(id));
    const avg = vals.reduce((s,v)=>s+v,0)/vals.length;
    return `<tr>
      <td>${i+1}</td>
      <td><strong>${siswa?.nama || 'Siswa Dihapus'}</strong></td>
      <td>${siswa?.kelas || '-'}</td>
      <td><strong>${avg.toFixed(1)}</strong></td>
      <td>${getPredikat(avg)}</td>
      <td><span class="badge ${avg>=70?'badge-success':'badge-danger'}">${avg>=70?'Lulus':'Remedial'}</span></td>
    </tr>`;
  }).join('') || '<tr><td colspan="6" style="text-align:center;padding:30px;color:var(--text-muted);">Belum ada data nilai</td></tr>';
}

