// -------- DO IMPORT --------
function doImportSoal() {
  const src = soalImportSource;
  let mapelEl, levelEl, poinEl;

  if (src === 'word' || src === 'pdf') {
    mapelEl = document.getElementById(src + '-mapel');
    levelEl = document.getElementById(src + '-level');
    poinEl  = document.getElementById(src + '-poin');
    if (!mapelEl.value) { showNotif('⚠️ Pilih mata pelajaran terlebih dahulu!', 'var(--warning)'); return; }

    let added = 0;
    soalImportParsed.forEach((s, idx) => {
      if (!s.pertanyaan.trim()) return;
      const tipe = Object.keys(s.opsi).length >= 2 ? 'Pilihan Ganda' : (s.kunci ? 'Isian Singkat' : 'Uraian');
      state.soal.push({
        id: Date.now() + Math.random(),
        mapel: mapelEl.value,
        tipe,
        level: levelEl.value,
        poin: parseInt(poinEl.value) || 10,
        pertanyaan: s.pertanyaan,
        opsiA: s.opsi['A'] || '',
        opsiB: s.opsi['B'] || '',
        opsiC: s.opsi['C'] || '',
        opsiD: s.opsi['D'] || '',
        kunci: s.kunci || '',
        pembahasan: s.pembahasan || '',
        guruId: (currentUser && currentUser.role === 'guru') ? currentUser.data.id : null,
        guruNama: (currentUser && currentUser.role === 'guru') ? currentUser.data.nama : 'Admin'
      });
      added++;
    });
    finishSoalImport(added, src);

  } else if (src === 'gform') {
    mapelEl = document.getElementById('gform-mapel');
    levelEl = null;
    poinEl  = document.getElementById('gform-poin');
    const tipeDefault = document.getElementById('gform-tipe').value;
    if (!mapelEl.value) { showNotif('⚠️ Pilih mata pelajaran terlebih dahulu!', 'var(--warning)'); return; }

    // If we have paste-parsed soal, use those
    if (soalImportParsed.length > 0) {
      let added = 0;
      soalImportParsed.forEach(s => {
        if (!s.pertanyaan.trim()) return;
        const tipe = Object.keys(s.opsi).length >= 2 ? 'Pilihan Ganda' : tipeDefault;
        state.soal.push({
          id: Date.now() + Math.random(),
          mapel: mapelEl.value, tipe, level: 'Sedang',
          poin: parseInt(poinEl.value) || 5,
          pertanyaan: s.pertanyaan,
          opsiA: s.opsi['A'] || '', opsiB: s.opsi['B'] || '',
          opsiC: s.opsi['C'] || '', opsiD: s.opsi['D'] || '',
          kunci: s.kunci || '', pembahasan: s.pembahasan || '',
          guruId: (currentUser && currentUser.role === 'guru') ? currentUser.data.id : null,
          guruNama: (currentUser && currentUser.role === 'guru') ? currentUser.data.nama : 'Admin'
        });
        added++;
      });
      finishSoalImport(added, src);
      return;
    }

    // Fallback: manual rows
    const rows = document.querySelectorAll('#gform-soal-manual-area > div');
    let added = 0;
    rows.forEach(row => {
      const idMatch = row.id.match(/gform-row-(\d+)/);
      if (!idMatch) return;
      const id = idMatch[1];
      const pertanyaan = document.getElementById('gfq-text-'+id)?.value.trim();
      if (!pertanyaan) return;
      state.soal.push({
        id: Date.now() + Math.random(),
        mapel: mapelEl.value,
        tipe: tipeDefault,
        level: 'Sedang',
        poin: parseInt(poinEl.value) || 5,
        pertanyaan,
        opsiA: document.getElementById('gfq-a-'+id)?.value || '',
        opsiB: document.getElementById('gfq-b-'+id)?.value || '',
        opsiC: document.getElementById('gfq-c-'+id)?.value || '',
        opsiD: document.getElementById('gfq-d-'+id)?.value || '',
        kunci: document.getElementById('gfq-kunci-'+id)?.value || '',
        pembahasan: document.getElementById('gfq-pembahasan-'+id)?.value || '',
        guruId: (currentUser && currentUser.role === 'guru') ? currentUser.data.id : null,
        guruNama: (currentUser && currentUser.role === 'guru') ? currentUser.data.nama : 'Admin'
      });
      added++;
    });
    finishSoalImport(added, src);
  }
}

function finishSoalImport(added, src) {
  save();
  renderSoal();
  document.getElementById('badge-soal').textContent = state.soal.length;
  document.getElementById('stat-total-soal').textContent = state.soal.length;

  const srcLabel = src === 'word' ? 'File Word' : src === 'pdf' ? 'File PDF' : 'Google Form';
  const resultHtml = `
    <div style="background:#d1fae5;border-left:4px solid var(--success);border-radius:10px;padding:14px;font-size:13.5px;display:flex;align-items:center;gap:12px;">
      <span style="font-size:28px;">✅</span>
      <div>
        <strong>Import dari ${srcLabel} berhasil!</strong><br>
        <span style="color:#065f46;">Ditambahkan <strong>${added}</strong> soal ke Bank Soal</span>
      </div>
    </div>`;
  document.getElementById('import-soal-result').innerHTML = resultHtml;
  document.getElementById('import-soal-result').style.display = '';

  addActivity(`Import soal dari ${srcLabel}: +${added} soal ditambahkan`);
  showNotif(`✅ ${added} soal berhasil diimport dari ${srcLabel}!`);
  closeModal('modal-import-soal');
  resetAllSoalImport();
}

