function tambahGuru() {
  const nama = document.getElementById('g-nama').value.trim();
  const ttl  = document.getElementById('g-ttl').value;
  if (!nama) { showNotif('⚠️ Nama guru wajib diisi!','var(--warning)'); return; }
  const guru = {
    id: Date.now(), nip: document.getElementById('g-nip').value.trim(),
    nik: document.getElementById('g-nik').value.trim(), nama,
    jk: document.getElementById('g-jk').value, ttl,
    mapel: document.getElementById('g-mapel').value,
    jabatan: document.getElementById('g-jabatan').value,
    hp: document.getElementById('g-hp').value,
    email: document.getElementById('g-email').value,
    pendidikan: document.getElementById('g-pendidikan').value,
    status: document.getElementById('g-status').value,
    alamat: document.getElementById('g-alamat').value,
    akunAktif: true
  };
  state.guru.push(guru);
  save();
  renderGuru();
  closeModal('modal-guru');
  showNotif(`✅ Guru "${nama}" berhasil ditambahkan!`);
  addActivity(`Guru baru: ${nama} (${guru.mapel || 'Belum ada mapel'})`);
  document.getElementById('badge-guru').textContent = state.guru.length;
  ['g-nip','g-nik','g-nama','g-ttl','g-hp','g-email','g-alamat'].forEach(id => document.getElementById(id).value = '');
}

function renderGuru(list) {
  const data = list || state.guru;
  const tbody = document.getElementById('tbody-guru');
  if (!tbody) return;
  if (data.length === 0) {
    tbody.innerHTML = `<tr><td colspan="9" style="text-align:center;padding:40px;color:var(--text-muted);">
      <div style="font-size:36px;margin-bottom:8px;">👨‍🏫</div>Belum ada data guru. Tambahkan guru atau import dari Excel.</td></tr>`;
    return;
  }
  tbody.innerHTML = data.map((g,i) => {
    const pw = formatTtlPassword(g.ttl);
    return `<tr>
      <td>${i+1}</td>
      <td><code style="font-size:11px;background:#f1f5f9;padding:2px 6px;border-radius:4px;">${g.nip||'-'}</code></td>
      <td><strong>${g.nama}</strong><br><span style="font-size:11px;color:var(--text-muted);">${g.jabatan||''}</span></td>
      <td><span class="tag">${g.mapel||'-'}</span></td>
      <td style="font-size:12px;">${g.ttl ? new Date(g.ttl+'T00:00:00').toLocaleDateString('id-ID') : '-'}</td>
      <td style="font-size:12px;">${g.hp||'-'}</td>
      <td><span class="badge ${g.status==='Aktif'?'badge-success':g.status==='Pensiun'?'badge-gray':'badge-warning'}">${g.status}</span></td>
      <td>
        ${g.akunAktif ? '<span class="badge badge-success">Aktif</span>' : '<span class="badge badge-gray">Nonaktif</span>'}
      </td>
      <td style="white-space:nowrap;">
        <button class="btn btn-sm btn-outline" onclick="showDetailGuru(${g.id})" style="padding:4px 8px;font-size:11px;">👁️</button>
        <button class="btn btn-sm btn-primary" onclick="showAkunIndividu('guru',${g.id})" style="padding:4px 8px;font-size:11px;">🔐</button>
        <button class="btn btn-sm" onclick="hapusGuru(${g.id})" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️</button>
      </td>
    </tr>`;
  }).join('');
  document.getElementById('badge-guru').textContent = state.guru.length;
}

function filterGuru() {
  const q = document.getElementById('search-guru').value.toLowerCase();
  const status = document.getElementById('filter-status-guru').value;
  const filtered = state.guru.filter(g =>
    (g.nama.toLowerCase().includes(q) || (g.nip||'').includes(q) || (g.mapel||'').toLowerCase().includes(q)) &&
    (!status || g.status === status)
  );
  renderGuru(filtered);
}

function hapusGuru(id) {
  if (!confirm('Yakin hapus guru ini?')) return;
  const g = state.guru.find(x => x.id === id);
  state.guru = state.guru.filter(x => x.id !== id);
  save();
  renderGuru();
  showNotif('🗑️ Data guru dihapus!','var(--danger)');
  if (g) addActivity(`Guru dihapus: ${g.nama}`);
}

