// ===== AKUN GURU =====

function switchAkunTab(tab) {
  document.getElementById('akun-pane-guru').style.display = tab==='guru' ? '' : 'none';
  document.getElementById('akun-pane-siswa').style.display = tab==='siswa' ? '' : 'none';
  document.querySelectorAll('#akun-tabs .tab').forEach((t,i) => {
    const active = (tab==='guru' && i===0) || (tab==='siswa' && i===1);
    t.classList.toggle('active', active);
  });
  if (tab==='guru') renderAkunGuru();
  else { populateAkunKelasFilter(); renderAkunSiswa(); }
}

function formatTtlPassword(ttl) {
  if (!ttl) return '';
  // Accepts YYYY-MM-DD → DDMMYYYY
  if (/^\d{4}-\d{2}-\d{2}$/.test(ttl)) {
    const [y,m,d] = ttl.split('-');
    return d + m + y;
  }
  return ttl.replace(/[-\/\.]/g,'');
}

function normalizeDateStr(raw) {
  if (!raw) return '';
  // Try various formats
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  // DD/MM/YYYY or DD-MM-YYYY
  const m = raw.match(/^(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{4})$/);
  if (m) return `${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;
  // Excel serial date number
  if (/^\d{5}$/.test(raw)) {
    const d = new Date(Math.round((parseFloat(raw)-25569)*86400*1000));
    return d.toISOString().split('T')[0];
  }
  return raw;
}

function generateAkunGuru() {
  if (state.guru.length === 0) { showNotif('⚠️ Belum ada data guru!','var(--warning)'); return; }
  renderAkunGuru();
  showNotif(`✅ Akun untuk ${state.guru.length} guru berhasil digenerate!`);
}

function renderAkunGuru() {
  const tbody = document.getElementById('tbody-akun-guru');
  if (!tbody) return;
  if (state.guru.length === 0) {
    tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:30px;color:var(--text-muted);">Belum ada data guru</td></tr>`;
    return;
  }
  tbody.innerHTML = state.guru.map((g,i) => {
    const pw = formatTtlPassword(g.ttl);
    return `<tr>
      <td>${i+1}</td>
      <td><strong>${g.nama}</strong></td>
      <td><span class="tag">${g.mapel||'-'}</span></td>
      <td style="font-family:monospace;font-size:13px;background:#eff6ff;">${g.nama}</td>
      <td style="font-family:monospace;font-size:13px;background:#d1fae5;">
        ${pw || '<span style="color:#ef4444;font-size:11px;">⚠️ Tgl lahir belum ada</span>'}
      </td>
      <td><span class="badge ${g.akunAktif?'badge-success':'badge-gray'}">${g.akunAktif?'Aktif':'Nonaktif'}</span></td>
      <td style="white-space:nowrap;">
        <button class="btn btn-sm btn-primary" onclick="showAkunIndividu('guru',${g.id})" style="padding:4px 8px;font-size:11px;">🔐 Lihat</button>
        <button class="btn btn-sm btn-outline" onclick="toggleAkunGuru(${g.id})" style="padding:4px 8px;font-size:11px;">${g.akunAktif?'🚫 Nonaktifkan':'✅ Aktifkan'}</button>
      </td>
    </tr>`;
  }).join('');
}

function toggleAkunGuru(id) {
  const g = state.guru.find(x => x.id === id);
  if (!g) return;
  g.akunAktif = !g.akunAktif;
  save(); renderAkunGuru();
  showNotif(`${g.akunAktif ? '✅ Akun diaktifkan' : '🚫 Akun dinonaktifkan'}: ${g.nama}`);
}

function downloadAkunGuru() {
  if (state.guru.length === 0) { showNotif('⚠️ Belum ada data guru!','var(--warning)'); return; }
  const doExport = () => {
    const rows = [['No','Nama Guru','Mapel','Username','Password','Status Akun','Tgl Lahir']];
    state.guru.forEach((g,i) => {
      rows.push([i+1, g.nama, g.mapel||'-', g.nama, formatTtlPassword(g.ttl)||'Belum ada', g.akunAktif?'Aktif':'Nonaktif', g.ttl||'-']);
    });
    const ws = XLSX.utils.aoa_to_sheet(rows);
    ws['!cols'] = [{wch:5},{wch:30},{wch:25},{wch:30},{wch:15},{wch:12},{wch:12}];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Akun Guru');
    XLSX.writeFile(wb, 'akun_guru_pkbm_cendikia.xlsx');
    showNotif('✅ File akun guru berhasil diunduh!');
  };
  if (typeof XLSX !== 'undefined') doExport();
  else { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; s.onload=doExport; document.head.appendChild(s); }
}

// ===== AKUN SISWA =====

function populateAkunKelasFilter() {
  const sel = document.getElementById('akun-filter-kelas');
  if (!sel) return;
  const kelas = [...new Set(state.siswa.map(s => s.kelas).filter(Boolean))].sort();
  sel.innerHTML = '<option value="">Semua Kelas</option>' + kelas.map(k => `<option>${k}</option>`).join('');
}

function renderAkunSiswa() {
  const filterKelas = document.getElementById('akun-filter-kelas')?.value || '';
  const data = state.siswa.filter(s => !filterKelas || s.kelas === filterKelas);
  const tbody = document.getElementById('tbody-akun-siswa');
  if (!tbody) return;
  if (data.length === 0) {
    tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;padding:30px;color:var(--text-muted);">Belum ada data siswa ${filterKelas?'di kelas '+filterKelas:''}</td></tr>`;
    return;
  }
  tbody.innerHTML = data.map((s,i) => {
    const pw = formatTtlPassword(s.ttl);
    return `<tr>
      <td>${i+1}</td>
      <td><strong>${s.nama}</strong></td>
      <td><code style="font-size:11px;">${s.nisn||'-'}</code></td>
      <td><span class="tag">${s.kelas||'-'}</span></td>
      <td style="font-family:monospace;font-size:13px;background:#eff6ff;">${s.nisn||'<span style="color:#ef4444;font-size:11px;">⚠️ NISN kosong</span>'}</td>
      <td style="font-family:monospace;font-size:13px;background:#d1fae5;">
        ${pw || '<span style="color:#ef4444;font-size:11px;">⚠️ Tgl lahir belum ada</span>'}
      </td>
      <td><span class="badge badge-success">Aktif</span></td>
      <td>
        <button class="btn btn-sm btn-primary" onclick="showAkunIndividu('siswa',${s.id})" style="padding:4px 8px;font-size:11px;">🔐 Lihat</button>
      </td>
    </tr>`;
  }).join('');
}

function downloadAkunSiswa() {
  if (state.siswa.length === 0) { showNotif('⚠️ Belum ada data siswa!','var(--warning)'); return; }
  const doExport = () => {
    const rows = [['No','Nama Siswa','NISN','Kelas','Username (NISN)','Password (Tgl Lahir)','Status']];
    state.siswa.forEach((s,i) => {
      rows.push([i+1, s.nama, s.nisn||'-', s.kelas||'-', s.nisn||'-', formatTtlPassword(s.ttl)||'Belum ada', 'Aktif']);
    });
    const ws = XLSX.utils.aoa_to_sheet(rows);
    ws['!cols'] = [{wch:5},{wch:30},{wch:14},{wch:14},{wch:14},{wch:14},{wch:10}];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Akun Siswa');
    XLSX.writeFile(wb, 'akun_siswa_pkbm_cendikia.xlsx');
    showNotif('✅ File akun siswa berhasil diunduh!');
  };
  if (typeof XLSX !== 'undefined') doExport();
  else { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; s.onload=doExport; document.head.appendChild(s); }
}

function downloadAkunSiswaKelas() {
  const filterKelas = document.getElementById('akun-filter-kelas')?.value || '';
  if (!filterKelas) { showNotif('⚠️ Pilih kelas terlebih dahulu untuk download per kelas!','var(--warning)'); return; }
  const data = state.siswa.filter(s => s.kelas === filterKelas);
  if (data.length === 0) { showNotif('⚠️ Tidak ada siswa di kelas tersebut!','var(--warning)'); return; }
  const doExport = () => {
    const rows = [['No','Nama Siswa','NISN','Kelas','Username (NISN)','Password (Tgl Lahir)']];
    data.forEach((s,i) => rows.push([i+1, s.nama, s.nisn||'-', s.kelas||'-', s.nisn||'-', formatTtlPassword(s.ttl)||'Belum ada']));
    const ws = XLSX.utils.aoa_to_sheet(rows);
    ws['!cols'] = [{wch:5},{wch:30},{wch:14},{wch:14},{wch:14},{wch:14}];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `Akun ${filterKelas}`);
    XLSX.writeFile(wb, `akun_siswa_${filterKelas.replace(/\s+/g,'_')}_pkbm.xlsx`);
    showNotif(`✅ Akun siswa ${filterKelas} berhasil diunduh!`);
  };
  if (typeof XLSX !== 'undefined') doExport();
  else { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; s.onload=doExport; document.head.appendChild(s); }
}

