// ===== LOGO PKBM MANAGEMENT =====
function gantiLogoPKBM(event) {
  const file = event.target.files[0];
  if (!file) return;
  if (!file.type.startsWith('image/')) { showNotif('⚠️ Pilih file gambar (PNG/JPG)!','var(--warning)'); return; }
  const reader = new FileReader();
  reader.onload = function(e) {
    const dataUrl = e.target.result;
    localStorage.setItem('pkbm_logo', dataUrl);
    applyPKBMLogo(dataUrl);
    showNotif('✅ Logo PKBM berhasil diperbarui!');
  };
  reader.readAsDataURL(file);
}

function applyPKBMLogo(dataUrl) {
  if (!dataUrl) return;
  // Login logo
  const loginLogoImg = document.querySelector('.login-logo img');
  if (loginLogoImg) loginLogoImg.src = dataUrl;
  // Topbar logo
  const topbarImg = document.getElementById('topbar-pkbm-logo');
  const topbarTxt = document.getElementById('topbar-brand-text');
  if (topbarImg) { topbarImg.src = dataUrl; topbarImg.style.display = ''; }
  if (topbarTxt) topbarTxt.style.display = 'none';
  // Admin pengaturan preview
  const preview = document.getElementById('admin-pkbm-logo-preview');
  if (preview) preview.src = dataUrl;
}

function initPKBMLogo() {
  const loginLogoImg = document.querySelector('.login-logo img');
  const initialSrc = loginLogoImg ? loginLogoImg.src : '';
  const savedLogo = localStorage.getItem('pkbm_logo') || initialSrc;
  if (savedLogo) applyPKBMLogo(savedLogo);
  // Also update the admin preview
  const preview = document.getElementById('admin-pkbm-logo-preview');
  if (preview && savedLogo) preview.src = savedLogo;
}

