function uploadFotoGuru(event) {
  const file = event.target.files[0];
  if (!file) return;
  if (!['image/jpeg','image/jpg','image/png'].includes(file.type)) {
    showNotif('⚠️ Hanya file JPG/PNG yang diperbolehkan!','var(--warning)'); return;
  }
  if (file.size > 2 * 1024 * 1024) {
    showNotif('⚠️ Ukuran file maksimal 2MB!','var(--warning)'); return;
  }
  const reader = new FileReader();
  reader.onload = function(e) {
    const dataUrl = e.target.result;
    const g = currentUser.data;
    localStorage.setItem('guru_photo_' + g.id, dataUrl);
    // Update preview in profil body
    const preview = document.getElementById('guru-profil-photo-preview');
    if (preview) preview.innerHTML = `<img src="${dataUrl}" style="width:100%;height:100%;object-fit:cover;" alt="Foto">`;
    // Update portal avatar
    const avatarEl = document.getElementById('guru-portal-avatar');
    if (avatarEl) avatarEl.innerHTML = `<img src="${dataUrl}" style="width:64px;height:64px;border-radius:50%;object-fit:cover;" alt="Foto">`;
    // Update topbar avatar
    const topbarAvEl = document.getElementById('topbar-avatar');
    if (topbarAvEl) topbarAvEl.innerHTML = `<img src="${dataUrl}" style="width:36px;height:36px;border-radius:50%;object-fit:cover;" alt="">`;
    showNotif('✅ Foto profil berhasil diperbarui!');
  };
  reader.readAsDataURL(file);
}


