/* ─── Export File dengan Data Terintegrasi ─── */
function exportFileWithData() {
  try {
    showNotif('⏳ Sedang menyiapkan file export...');
    
    // Kumpulkan semua data saat ini
    const exportData = {
      siswa: state.siswa || [],
      guru: state.guru || [],
      soal: state.soal || [],
      ujian: state.ujian || [],
      ujian_online: state.ujian_online || [],
      jawaban_ujian: state.jawaban_ujian || [],
      mapel: state.mapel || [],
      nilai: state.nilai || [],
      activity: state.activity || [],
      fitur_baru: state.fitur_baru || [],
      fitur_respons: state.fitur_respons || [],
      naik_kelas: state.naik_kelas || {},
      flayer_files: state.flayer_files || {},
      sumber_belajar: state.sumber_belajar || [],
      perangkat_ajar: state.perangkat_ajar || [],
      video_pembelajaran: state.video_pembelajaran || [],
      admin_user: localStorage.getItem('pkbm_admin_user') || 'admin',
      admin_pass: localStorage.getItem('pkbm_admin_pass') || 'admin123',
    };
    
    // Baca HTML file saat ini
    const xhr = new XMLHttpRequest();
    // Ambil HTML dari halaman saat ini
    const htmlContent = document.documentElement.outerHTML;
    
    // Ganti placeholder PKBM_EMBEDDED_DATA dengan data asli
    const dataJson = JSON.stringify(exportData);
    const _pkbmStart = htmlContent.indexOf('var PKBM_EMBEDDED_DATA = ');
    const _pkbmEnd = htmlContent.indexOf('};', _pkbmStart) + 2;
    const _pkbmOld = htmlContent.slice(_pkbmStart, _pkbmEnd);
    const newHtml = _pkbmOld ? htmlContent.replace(_pkbmOld, 'var PKBM_EMBEDDED_DATA = ' + dataJson + ';') : htmlContent;
    
    // Buat dan download file
    const blob = new Blob([newHtml], { type: 'text/html;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const tgl = new Date().toISOString().slice(0,10).replace(/-/g,'');
    a.download = 'sistem-asesmen-pkbm-' + tgl + '.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    
    setTimeout(() => showNotif('✅ File berhasil diexport! ' + exportData.guru.length + ' guru, ' + exportData.siswa.length + ' siswa tersimpan dalam file.'), 800);
  } catch(e) {
    showNotif('❌ Gagal export: ' + e.message);
    console.error(e);
  }
}

/* ─── Logout ─── */
function doLogout() {
  if (!confirm('Yakin ingin keluar dari sistem?')) return;
  clearInterval(countdownInterval);
  currentUser = null;
  currentLoginRole = 'admin';
  sessionStorage.removeItem('pkbm_session'); // Hapus sesi

  // Reset form login
  const adminUser = document.getElementById('admin-user');
  const adminPass = document.getElementById('admin-pass');
  if (adminUser) adminUser.value = '';
  if (adminPass) adminPass.value = '';
  document.getElementById('login-error').style.display = 'none';
  
  // Reset login hints
  const hintEl = document.getElementById('login-role-hint');
  const passHint = document.getElementById('login-pass-hint');
  const badge = document.getElementById('role-detected-badge');
  if (hintEl) hintEl.textContent = '';
  if (passHint) passHint.textContent = 'Masukkan username untuk melihat petunjuk password';
  if (badge) badge.style.display = 'none';

  // Tampilkan login page
  const lp = document.getElementById('login-page');
  lp.style.opacity = '0';
  lp.style.display = 'flex';
  setTimeout(() => {
    lp.style.transition = 'opacity .3s ease';
    lp.style.opacity = '1';
  }, 10);

  // Reset body class
  document.body.classList.remove('role-admin','role-guru','role-siswa');
  // Hide timer bar
  const timerBar = document.getElementById('timer-bar');
  if (timerBar) timerBar.style.display = 'none';
}

/* ─── Override showPage agar blokir halaman admin untuk guru/siswa ─── */
const _origShowPage = showPage;
showPage = function(id) {
  const role = currentUser ? currentUser.role : 'admin';

  // Halaman yang hanya boleh diakses admin
  const adminOnly = ['dashboard','siswa','guru','ujian','pelaksanaan','akun','mapel','pengaturan','import','naik-kelas'];
  if (role !== 'admin' && adminOnly.includes(id)) {
    showNotif('⚠️ Anda tidak memiliki akses ke halaman ini!', 'var(--warning)');
    return;
  }
  _origShowPage(id);
};

