/* ─── Variabel global untuk ujian ─── */
let activeUjianId = null;
let countdownInterval = null;
let jawabanSiswa = {};

/* ─── Helper: Cek apakah kelas 12 ─── */
function isKelas12(kelas) {
  const k = (kelas||'').toLowerCase();
  return k.includes('xii') || k === 'kelas 12' || k.startsWith('12 ') || k.endsWith(' 12');
}

/* ─── Load daftar ujian untuk siswa ─── */
function loadUjianSiswa(type) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.getElementById('page-ujian-online').classList.add('active');
  
  const s = currentUser.data;
  const jenisLabel = type || (isKelas12(s.kelas) ? 'UPK' : 'UAS');
  
  document.getElementById('ujian-online-breadcrumb').textContent = jenisLabel;
  document.getElementById('ujian-online-title').textContent = (jenisLabel === 'UPK' ? '🎓' : '📝') + ' Daftar ' + jenisLabel;
  document.getElementById('ujian-online-subtitle').textContent = 'Ujian ' + jenisLabel + ' untuk kelas ' + (s.kelas||'-');

  const ujianTersedia = state.ujian_online.filter(u => {
    const kelasMatch = !u.kelas || u.kelas === s.kelas || u.kelas === 'Semua Kelas';
    const jenisMatch = u.jenis === jenisLabel;
    return kelasMatch && jenisMatch && u.published;
  });

  const container = document.getElementById('ujian-list-siswa');
  if (ujianTersedia.length === 0) {
    container.innerHTML = `<div class="empty-state">
      <div class="empty-icon">${jenisLabel === 'UPK' ? '🎓' : '📝'}</div>
      <h4>Tidak ada ujian ${jenisLabel} aktif</h4>
      <p>Guru belum menerbitkan ujian ${jenisLabel} untuk kelas ${s.kelas||'Anda'}</p>
    </div>`;
    return;
  }

  container.innerHTML = `<div style="display:grid;gap:16px;max-width:800px;margin:0 auto;">` +
    ujianTersedia.map(u => {
      const sudahDikerjakan = state.jawaban_ujian.find(j => j.ujianId === u.id && j.siswaId === s.id);
      const statusColor = sudahDikerjakan ? '#065f46' : '#4338ca';
      const statusBg = sudahDikerjakan ? '#d1fae5' : '#ede9fe';
      const statusText = sudahDikerjakan ? '✅ Sudah Dikerjakan' : '⏳ Belum Dikerjakan';
      
      return `<div class="card" style="border-left:4px solid ${statusColor};">
        <div class="card-body">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;">
            <div>
              <h4 style="font-size:16px;font-weight:800;margin-bottom:4px;">${u.nama}</h4>
              <p style="font-size:13px;color:#64748b;">${u.mapel} · ${u.kelas} · ${u.jenis}</p>
            </div>
            <span style="background:${statusBg};color:${statusColor};padding:4px 12px;border-radius:20px;font-size:12px;font-weight:700;">${statusText}</span>
          </div>
          <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:14px;font-size:13px;">
            <div style="background:#f8fafc;border-radius:8px;padding:10px;text-align:center;">
              <div style="color:#64748b;font-size:11px;">Jumlah Soal</div>
              <div style="font-weight:800;font-size:18px;color:#1e293b;">${(u.soalIds||[]).length}</div>
            </div>
            <div style="background:#f8fafc;border-radius:8px;padding:10px;text-align:center;">
              <div style="color:#64748b;font-size:11px;">Durasi</div>
              <div style="font-weight:800;font-size:18px;color:#1e293b;">${u.durasi} mnt</div>
            </div>
            <div style="background:#f8fafc;border-radius:8px;padding:10px;text-align:center;">
              <div style="color:#64748b;font-size:11px;">KKM</div>
              <div style="font-weight:800;font-size:18px;color:#1e293b;">${u.kkm}</div>
            </div>
          </div>
          ${u.keterangan ? `<div style="background:#fffbeb;border-radius:8px;padding:10px;font-size:12.5px;margin-bottom:12px;color:#92400e;">📋 ${u.keterangan}</div>` : ''}
          ${sudahDikerjakan 
            ? `<div style="background:#d1fae5;border-radius:8px;padding:12px;font-size:13.5px;color:#065f46;text-align:center;">
                <strong>Nilai Anda: ${sudahDikerjakan.nilai}</strong> | ${sudahDikerjakan.benar}/${(u.soalIds||[]).length} benar
              </div>` 
            : `<button onclick="mulaiMengerjakanUjian(${u.id})" style="width:100%;background:linear-gradient(135deg,#312e81,#4338ca);color:#fff;border:none;padding:12px;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;">
                📝 Mulai Kerjakan Ujian
              </button>`
          }
        </div>
      </div>`;
    }).join('') + '</div>';
}

/* ─── Mulai mengerjakan ujian ─── */
function mulaiMengerjakanUjian(ujianId) {
  const u = state.ujian_online.find(x => x.id === ujianId);
  if (!u) return;

  if (!confirm(`Anda akan memulai ujian "${u.nama}".\nDurasi: ${u.durasi} menit\nJumlah soal: ${(u.soalIds||[]).length} butir\n\nPastikan Anda siap. Klik OK untuk mulai.`)) return;

  activeUjianId = ujianId;
  jawabanSiswa = {};

  const soalList = (u.soalIds || []).map(sid => state.soal.find(s => s.id === sid || s.id === parseInt(sid))).filter(Boolean);
  
  document.getElementById('ujian-nama-timer').textContent = u.nama;
  
  const container = document.getElementById('soal-container');
  container.innerHTML = soalList.map((soal, idx) => {
    const opsi = ['A','B','C','D'].filter(o => soal['opsi'+o]);
    const isEssay = soal.tipe === 'Uraian';
    const isIsian = soal.tipe === 'Isian Singkat';
    
    return `<div class="card" id="soal-card-${soal.id}" style="transition:.2s;">
      <div class="card-body">
        <div style="display:flex;gap:12px;align-items:flex-start;margin-bottom:14px;">
          <div style="min-width:36px;height:36px;background:linear-gradient(135deg,#312e81,#4338ca);border-radius:10px;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:800;font-size:15px;flex-shrink:0;">${idx+1}</div>
          <div style="font-size:14.5px;font-weight:600;color:#1e293b;line-height:1.6;">${soal.pertanyaan}</div>
        </div>
        ${isEssay || isIsian ? `
          <textarea class="form-control" id="jawab-${soal.id}" placeholder="${isEssay ? 'Tulis jawaban Anda di sini...' : 'Tulis jawaban singkat...'}" 
            style="min-height:${isEssay?'100':'50'}px;" 
            oninput="recordJawaban('${soal.id}', this.value)"></textarea>
        ` : `
          <div style="display:grid;gap:8px;">
            ${opsi.map(o => `
              <label id="opt-${soal.id}-${o}" style="display:flex;align-items:center;gap:12px;padding:12px 14px;border:2px solid #e2e8f0;border-radius:10px;cursor:pointer;transition:.15s;"
                onmouseover="if(!document.querySelector('[name=soal-${soal.id}]:checked,[value=${o}]'))this.style.borderColor='#818cf8'"
                onmouseout="this.style.borderColor=(jawabanSiswa['${soal.id}']==='${o}')?'#4338ca':'#e2e8f0'">
                <input type="radio" name="soal-${soal.id}" value="${o}" 
                  onchange="recordJawabanPG('${soal.id}', '${o}')"
                  style="accent-color:#4338ca;width:18px;height:18px;">
                <span style="font-weight:700;color:#4338ca;min-width:22px;">${o}.</span>
                <span style="font-size:13.5px;">${soal['opsi'+o]}</span>
              </label>`).join('')}
          </div>
        `}
      </div>
    </div>`;
  }).join('');

  document.getElementById('submit-info').textContent = `Ujian: ${u.nama} · ${soalList.length} soal`;
  updateProgressBar(soalList);

  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.getElementById('page-ruang-ujian').classList.add('active');
  document.getElementById('timer-bar').style.display = 'flex';

  startCountdown(u.durasi * 60);
}

function recordJawabanPG(soalId, jawaban) {
  jawabanSiswa[soalId] = jawaban;
  ['A','B','C','D'].forEach(o => {
    const el = document.getElementById(`opt-${soalId}-${o}`);
    if (!el) return;
    el.style.borderColor = (o === jawaban) ? '#4338ca' : '#e2e8f0';
    el.style.background = (o === jawaban) ? '#ede9fe' : '';
  });
  const u = state.ujian_online.find(x => x.id === activeUjianId);
  if (u) updateProgressBar((u.soalIds||[]).map(sid => state.soal.find(s => s.id === sid || s.id === parseInt(sid))).filter(Boolean));
}

function recordJawaban(soalId, jawaban) {
  jawabanSiswa[soalId] = jawaban;
  const u = state.ujian_online.find(x => x.id === activeUjianId);
  if (u) updateProgressBar((u.soalIds||[]).map(sid => state.soal.find(s => s.id === sid || s.id === parseInt(sid))).filter(Boolean));
}

function updateProgressBar(soalList) {
  const dijawab = soalList.filter(s => jawabanSiswa[s.id] && jawabanSiswa[s.id].toString().trim()).length;
  const total = soalList.length;
  document.getElementById('soal-progress-text').textContent = `${dijawab} / ${total} dijawab`;
  document.getElementById('soal-progress-bar').style.width = (total ? (dijawab/total*100) : 0) + '%';
}

function startCountdown(seconds) {
  clearInterval(countdownInterval);
  let remaining = seconds;
  const display = document.getElementById('countdown-timer');
  const bar = document.getElementById('timer-bar');
  
  function updateTimer() {
    const m = Math.floor(remaining / 60);
    const s = remaining % 60;
    display.textContent = String(m).padStart(2,'0') + ':' + String(s).padStart(2,'0');
    
    if (remaining <= 300) {
      bar.style.background = 'linear-gradient(135deg,#7f1d1d,#dc2626)';
    } else if (remaining <= 600) {
      bar.style.background = 'linear-gradient(135deg,#78350f,#d97706)';
    }
    
    if (remaining <= 0) {
      clearInterval(countdownInterval);
      display.textContent = '00:00';
      showNotif('⏰ Waktu ujian habis! Jawaban otomatis dikumpulkan.', 'var(--warning)');
      setTimeout(submitUjian, 1500);
    }
    remaining--;
  }
  updateTimer();
  countdownInterval = setInterval(updateTimer, 1000);
}

/* ─── Submit jawaban ujian ─── */
function submitUjian() {
  clearInterval(countdownInterval);
  document.getElementById('timer-bar').style.display = 'none';

  const u = state.ujian_online.find(x => x.id === activeUjianId);
  if (!u) { showNotif('⚠️ Data ujian tidak ditemukan!','var(--warning)'); return; }
  const s = currentUser.data;

  const soalList = (u.soalIds || []).map(sid => state.soal.find(x => x.id === sid || x.id === parseInt(sid))).filter(Boolean);
  
  let benar = 0, salah = 0, esai = 0;
  soalList.forEach(soal => {
    const jawaban = jawabanSiswa[soal.id];
    if (soal.tipe === 'Pilihan Ganda' || soal.tipe === 'Benar/Salah') {
      if (jawaban && soal.kunci && jawaban.trim().toUpperCase() === soal.kunci.trim().toUpperCase()) benar++;
      else if (jawaban) salah++;
    } else if (soal.tipe === 'Isian Singkat') {
      if (jawaban && soal.kunci && jawaban.trim().toLowerCase() === soal.kunci.trim().toLowerCase()) benar++;
      else if (jawaban) salah++;
    } else {
      if (jawaban) esai++;
    }
  });

  const totalTerkoreksi = soalList.filter(s => s.tipe !== 'Uraian').length;
  const nilai = totalTerkoreksi > 0 ? Math.round((benar / totalTerkoreksi) * 100) : null;
  const nilaiStr = nilai !== null ? nilai : 'Menunggu Koreksi';
  const lulus = nilai !== null ? (nilai >= parseInt(u.kkm) ? 'Lulus' : 'Remedial') : '-';

  const jawabanEntry = {
    id: Date.now(),
    ujianId: u.id,
    ujianNama: u.nama,
    siswaId: s.id,
    siswaNama: s.nama,
    siswaKelas: s.kelas,
    siswaNisn: s.nisn,
    jawaban: { ...jawabanSiswa },
    benar, salah, esai,
    nilai: nilaiStr,
    lulus,
    tanggal: new Date().toLocaleString('id-ID'),
    mapel: u.mapel,
    kkm: u.kkm
  };

  state.jawaban_ujian.push(jawabanEntry);
  
  if (nilai !== null) {
    state.nilai.push({
      id: Date.now() + 1,
      siswaId: s.id,
      nama: s.nama,
      kelas: s.kelas,
      nisn: s.nisn,
      mapel: u.mapel,
      jenis: u.jenis,
      nilai: nilai,
      akhir: nilai,
      sumber: 'ujian_online',
      ujianId: u.id
    });
  }
  
  save();
  addActivity(`${s.nama} mengerjakan ujian: ${u.nama} — Nilai: ${nilaiStr}`);

  document.getElementById('hasil-submit-body').innerHTML = `
    <div style="text-align:center;padding:20px;">
      <div style="font-size:64px;margin-bottom:12px;">${nilai !== null ? (nilai >= parseInt(u.kkm) ? '🎉' : '😔') : '📝'}</div>
      <h3 style="font-size:20px;font-weight:800;margin-bottom:4px;">${u.nama}</h3>
      <p style="color:#64748b;margin-bottom:20px;">${u.mapel} · ${u.kelas}</p>
      ${nilai !== null ? `
        <div style="background:${nilai>=parseInt(u.kkm)?'#d1fae5':'#fee2e2'};border-radius:16px;padding:24px;margin-bottom:16px;">
          <div style="font-size:14px;color:#64748b;margin-bottom:4px;">NILAI ANDA</div>
          <div style="font-size:56px;font-weight:900;color:${nilai>=parseInt(u.kkm)?'#065f46':'#991b1b'};">${nilai}</div>
          <div style="font-size:14px;font-weight:700;color:${nilai>=parseInt(u.kkm)?'#065f46':'#991b1b'};">${lulus}</div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;font-size:13px;">
          <div style="background:#f8fafc;border-radius:10px;padding:12px;text-align:center;">
            <div style="color:#64748b;">Jawaban Benar</div>
            <div style="font-weight:800;font-size:20px;color:#065f46;">${benar}</div>
          </div>
          <div style="background:#f8fafc;border-radius:10px;padding:12px;text-align:center;">
            <div style="color:#64748b;">Jawaban Salah</div>
            <div style="font-weight:800;font-size:20px;color:#991b1b;">${salah}</div>
          </div>
        </div>
        <p style="font-size:12px;color:#64748b;margin-top:12px;">KKM: ${u.kkm} | Total soal: ${soalList.length}</p>
      ` : `
        <div style="background:#fef3c7;border-radius:12px;padding:20px;">
          <p style="font-weight:700;color:#92400e;">Jawaban Anda telah dikirim!</p>
          <p style="font-size:13px;color:#92400e;">Ujian uraian/esai memerlukan koreksi manual oleh guru.</p>
        </div>
      `}
    </div>`;
  openModal('modal-hasil-submit');
  jawabanSiswa = {};
  activeUjianId = null;
}

function kembaliPortalSiswa() {
  buildSiswaPortal();
  showPageRaw('portal-siswa');
}

/* ─── Guru: Load dan tampilkan ujian online ─── */
function loadUjianGuru() {
  if (!currentUser) return;
  const g = currentUser.data;
  const role = currentUser.role;
  
  const ujianGuru = role === 'admin' 
    ? state.ujian_online 
    : state.ujian_online.filter(u => u.guruId === g.id || u.guruNama === g.nama);
  
  const cont = document.getElementById('list-ujian-guru');
  if (!cont) return;
  
  if (ujianGuru.length === 0) {
    cont.innerHTML = '<div class="empty-state"><div class="empty-icon">📋</div><h4>Belum ada ujian</h4><p>Klik "Buat Ujian Online Baru" untuk membuat ujian pertama</p></div>';
    return;
  }

  cont.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:16px;">` +
    ujianGuru.map(u => {
      const hasilCount = state.jawaban_ujian.filter(j => j.ujianId === u.id).length;
      return `<div class="card" style="border-left:4px solid ${u.published ? '#4338ca' : '#94a3b8'};">
        <div class="card-body">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px;">
            <div>
              <h4 style="font-size:15px;font-weight:800;">${u.nama}</h4>
              <p style="font-size:12px;color:#64748b;">${u.mapel} · ${u.kelas} · ${u.jenis}</p>
              <p style="font-size:11px;color:#94a3b8;margin-top:2px;">Dibuat oleh: ${u.guruNama||'Admin'}</p>
            </div>
            <span style="background:${u.published?'#dbeafe':'#f1f5f9'};color:${u.published?'#1d4ed8':'#475569'};padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700;">${u.published?'✅ Published':'📌 Draft'}</span>
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px;font-size:12px;">
            <div style="background:#f8fafc;border-radius:8px;padding:8px;text-align:center;">
              <div style="color:#64748b;">Soal</div>
              <div style="font-weight:800;">${(u.soalIds||[]).length}</div>
            </div>
            <div style="background:#f8fafc;border-radius:8px;padding:8px;text-align:center;">
              <div style="color:#64748b;">Durasi</div>
              <div style="font-weight:800;">${u.durasi} mnt</div>
            </div>
            <div style="background:#d1fae5;border-radius:8px;padding:8px;text-align:center;">
              <div style="color:#065f46;">Dikerjakan</div>
              <div style="font-weight:800;color:#065f46;">${hasilCount} siswa</div>
            </div>
          </div>
          <div style="display:flex;gap:6px;flex-wrap:wrap;">
            <button onclick="lihatHasilUjian(${u.id})" class="btn btn-sm btn-primary">📊 Lihat Hasil</button>
            ${!u.published ? `<button onclick="publishUjian(${u.id})" class="btn btn-sm btn-success">📢 Publish</button>` : ''}
            <button onclick="hapusUjianOnline(${u.id})" style="padding:5px 10px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:7px;cursor:pointer;">🗑️</button>
          </div>
        </div>
      </div>`;
    }).join('') + '</div>';
}

function publishUjian(id) {
  const u = state.ujian_online.find(x => x.id === id);
  if (!u) return;
  u.published = true;
  save();
  loadUjianGuru();
  showNotif(`📢 Ujian "${u.nama}" berhasil dipublish! Siswa sudah bisa mengakses.`);
  addActivity(`Ujian dipublish: ${u.nama}`);
}

function hapusUjianOnline(id) {
  if (!confirm('Hapus ujian ini? Semua jawaban siswa juga akan terhapus.')) return;
  state.ujian_online = state.ujian_online.filter(x => x.id !== id);
  state.jawaban_ujian = state.jawaban_ujian.filter(x => x.ujianId !== id);
  save();
  loadUjianGuru();
  showNotif('🗑️ Ujian dihapus!','var(--danger)');
}

/* ─── Guru: Buat ujian online baru ─── */
function openModalUjianOnline() {
  const opts = getMapelOptions();
  const mapelSel = document.getElementById('uo-mapel');
  if (mapelSel) {
    mapelSel.innerHTML = '<option value="">-- Pilih Mapel --</option>';
    opts.forEach(m => mapelSel.appendChild(new Option(m,m)));
  }
  loadSoalPicker('');
}

function loadSoalPicker(mapelVal) {
  const visibleSoal = getSoalVisible();
  const soalFiltered = mapelVal ? visibleSoal.filter(s => s.mapel === mapelVal) : visibleSoal;
  const countEl = document.getElementById('soal-tersedia-count');
  if (countEl) countEl.textContent = soalFiltered.length;
  
  const container = document.getElementById('soal-picker-list');
  if (!container) return;
  
  if (soalFiltered.length === 0) {
    container.innerHTML = `<div style="text-align:center;padding:20px;color:#64748b;font-size:13px;">
      ${mapelVal ? 'Belum ada soal untuk mapel ' + mapelVal + '. Tambahkan soal di menu Bank Soal dulu.' : 'Pilih mapel untuk memfilter soal atau tambahkan soal di Bank Soal.'}
    </div>`;
    return;
  }
  
  container.innerHTML = soalFiltered.map(s => `
    <label style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-radius:8px;cursor:pointer;margin-bottom:4px;border:1.5px solid #f1f5f9;transition:.1s;" 
      onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
      <input type="checkbox" value="${s.id}" style="margin-top:3px;accent-color:#4338ca;width:16px;height:16px;flex-shrink:0;" 
        onchange="updateSoalDipilih()">
      <div style="flex:1;min-width:0;">
        <div style="font-size:13px;font-weight:600;color:#1e293b;margin-bottom:4px;word-wrap:break-word;">${s.pertanyaan.length > 100 ? s.pertanyaan.substring(0,100)+'...' : s.pertanyaan}</div>
        <div style="display:flex;gap:6px;flex-wrap:wrap;">
          <span style="font-size:11px;background:#eff6ff;color:#1d4ed8;padding:2px 7px;border-radius:10px;">${s.tipe}</span>
          <span style="font-size:11px;background:#f1f5f9;color:#475569;padding:2px 7px;border-radius:10px;">${s.mapel}</span>
          <span style="font-size:11px;color:#64748b;">${s.poin||10} poin</span>
        </div>
      </div>
    </label>`).join('');
  updateSoalDipilih();
}

function updateSoalDipilih() {
  const checked = document.querySelectorAll('#soal-picker-list input[type=checkbox]:checked');
  const countEl = document.getElementById('soal-dipilih-count');
  if (countEl) countEl.textContent = checked.length + ' dipilih';
}

document.addEventListener('change', function(e) {
  if (e.target && e.target.id === 'uo-mapel') {
    loadSoalPicker(e.target.value);
  }
});

function tambahUjianOnline() {
  const nama = document.getElementById('uo-nama').value.trim();
  const mapel = document.getElementById('uo-mapel').value;
  const kelas = document.getElementById('uo-kelas').value;
  const durasi = parseInt(document.getElementById('uo-durasi').value) || 90;
  const kkm = parseInt(document.getElementById('uo-kkm').value) || 70;
  const jenis = document.getElementById('uo-jenis').value;
  const ket = document.getElementById('uo-ket').value;
  
  if (!nama || !mapel || !kelas) { showNotif('⚠️ Nama ujian, mapel, dan kelas wajib diisi!','var(--warning)'); return; }
  
  const checked = document.querySelectorAll('#soal-picker-list input[type=checkbox]:checked');
  if (checked.length === 0) { showNotif('⚠️ Pilih minimal 1 soal untuk ujian ini!','var(--warning)'); return; }
  
  const soalIds = Array.from(checked).map(cb => {
    const val = cb.value;
    const num = parseInt(val);
    return isNaN(num) ? val : num;
  });
  
  const g = currentUser ? currentUser.data : {};
  const ujian = {
    id: Date.now(), nama, mapel, kelas, durasi, kkm,
    jenis, keterangan: ket, soalIds,
    guruId: g.id || 0, guruNama: g.nama || 'Admin',
    published: false,
    tanggalBuat: new Date().toLocaleDateString('id-ID')
  };
  
  state.ujian_online.push(ujian);
  save();
  closeModal('modal-ujian-online');
  loadUjianGuru();
  showNotif(`✅ Ujian "${nama}" berhasil dibuat! Klik "Publish" agar siswa bisa mengakses.`);
  addActivity(`Ujian online dibuat: ${nama} (${mapel} · ${kelas}) oleh ${g.nama||'Admin'}`);
  
  ['uo-nama','uo-ket'].forEach(id => { const el = document.getElementById(id); if(el) el.value = ''; });
}

/* ─── Guru: Lihat hasil ujian ─── */
function lihatHasilUjian(ujianId) {
  const u = state.ujian_online.find(x => x.id === ujianId);
  if (!u) return;
  
  document.getElementById('hasil-breadcrumb').textContent = u.nama;
  document.getElementById('hasil-title').textContent = `📊 Hasil: ${u.nama}`;
  window._currentHasilUjianId = ujianId;
  
  const hasil = state.jawaban_ujian.filter(j => j.ujianId === ujianId);
  const tbody = document.getElementById('tbody-hasil-ujian');
  
  if (hasil.length === 0) {
    tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:30px;color:#64748b;">Belum ada siswa yang mengerjakan ujian ini</td></tr>';
  } else {
    tbody.innerHTML = hasil.map((h, idx) => {
      const nilaiNum = typeof h.nilai === 'number' ? h.nilai : parseInt(h.nilai);
      const ok = !isNaN(nilaiNum);
      const lulus = ok && nilaiNum >= parseInt(u.kkm);
      return `<tr>
        <td>${idx+1}</td>
        <td><strong>${h.siswaNama}</strong></td>
        <td>${h.siswaKelas||'-'}</td>
        <td style="font-size:12px;">${h.tanggal}</td>
        <td><span style="color:#065f46;font-weight:700;">${h.benar||0}</span></td>
        <td><span style="color:#991b1b;font-weight:700;">${h.salah||0}</span></td>
        <td>
          <span style="background:${ok?(lulus?'#d1fae5':'#fee2e2'):'#fef3c7'};color:${ok?(lulus?'#065f46':'#991b1b'):'#92400e'};padding:4px 12px;border-radius:20px;font-weight:800;font-size:13px;">${h.nilai}</span>
        </td>
        <td><span style="background:${lulus?'#d1fae5':ok?'#fee2e2':'#fef3c7'};color:${lulus?'#065f46':ok?'#991b1b':'#92400e'};padding:3px 10px;border-radius:12px;font-size:12px;font-weight:600;">${h.lulus||'-'}</span></td>
      </tr>`;
    }).join('');
  }
  
  showPageRaw('hasil-ujian');
}

/* ─── Export hasil ujian ─── */
function exportHasilUjian(format) {
  const ujianId = window._currentHasilUjianId;
  if (!ujianId) { showNotif('⚠️ Tidak ada data ujian!','var(--warning)'); return; }
  
  const u = state.ujian_online.find(x => x.id === ujianId);
  const hasil = state.jawaban_ujian.filter(j => j.ujianId === ujianId);
  
  if (hasil.length === 0) { showNotif('⚠️ Belum ada siswa yang mengerjakan!','var(--warning)'); return; }
  
  if (format === 'csv') {
    const header = ['No','Nama Siswa','NISN','Kelas','Tanggal','Jawaban Benar','Jawaban Salah','Nilai','Keterangan'];
    const rows = hasil.map((h,i) => [i+1, h.siswaNama, h.siswaNisn||'-', h.siswaKelas||'-', h.tanggal, h.benar||0, h.salah||0, h.nilai, h.lulus||'-']);
    const csv = [header, ...rows].map(r => r.map(c => `"${c}"`).join(',')).join('\n');
    const blob = new Blob(['\uFEFF'+csv], { type:'text/csv;charset=utf-8;' });
    const fname = `hasil_${(u?u.nama:'ujian').replace(/\s+/g,'_')}.csv`;
    downloadBlob(blob, fname);
    showNotif('✅ Export CSV berhasil!');
    return;
  }
  
  const doExport = () => {
    const data = [['No','Nama Siswa','NISN','Kelas','Tanggal','Benar','Salah','Nilai','Keterangan']];
    hasil.forEach((h,i) => data.push([i+1, h.siswaNama, h.siswaNisn||'-', h.siswaKelas||'-', h.tanggal, h.benar||0, h.salah||0, h.nilai, h.lulus||'-']));
    const ws = XLSX.utils.aoa_to_sheet(data);
    ws['!cols'] = [{wch:5},{wch:30},{wch:14},{wch:14},{wch:20},{wch:8},{wch:8},{wch:8},{wch:12}];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Hasil Ujian');
    const fname = `hasil_${(u?u.nama:'ujian').replace(/\s+/g,'_')}.xlsx`;
    XLSX.writeFile(wb, fname);
    showNotif('✅ Export Excel berhasil!');
  };
  if (typeof XLSX !== 'undefined') doExport();
  else { const sc=document.createElement('script'); sc.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; sc.onload=doExport; document.head.appendChild(sc); }
}

