/* ─── Style untuk animasi pulse timer ─── */
const _pulseStyle = document.createElement('style');
_pulseStyle.textContent = `
  @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.4} }
  #page-ruang-ujian { padding-top:80px !important; }
`;
document.head.appendChild(_pulseStyle);

// ===================================================================
// ============= SUMBER BELAJAR (ADMIN + GURU + SISWA) ===============
// ===================================================================

let sbCurrentFile = null;
function sbDragOver(e) { e.preventDefault(); document.getElementById('sb-drop-zone').style.borderColor='#7c3aed'; }
function sbDragLeave(e) { document.getElementById('sb-drop-zone').style.borderColor='#c4b5fd'; }
function sbDrop(e) { e.preventDefault(); sbDragLeave(e); const f=e.dataTransfer.files[0]; if(f) sbProcessFile(f); }
function sbHandleFile(e) { const f=e.target.files[0]; if(f) sbProcessFile(f); }
function sbProcessFile(file) {
  const allowed=['pdf','doc','docx','ppt','pptx','jpg','jpeg','png'];
  const ext=file.name.split('.').pop().toLowerCase();
  if(!allowed.includes(ext)){showNotif('⚠️ Format: PDF, Word, PPT, JPG, PNG','var(--warning)');return;}
  if(file.size>5*1024*1024){showNotif('⚠️ Maks 5MB untuk penyimpanan lokal!','var(--warning)');return;}
  sbCurrentFile=file;
  // Read file as base64 for storage
  const reader=new FileReader();
  reader.onload=function(e){
    sbCurrentFile._base64=e.target.result;
    document.getElementById('sb-file-info').style.display='';
    document.getElementById('sb-file-name').innerHTML='📄 <strong>'+file.name+'</strong> <span style="color:var(--text-muted)">('+( file.size/1024).toFixed(1)+' KB)</span>';
    document.getElementById('sb-drop-zone').style.display='none';
    showNotif('✅ File siap diupload: '+file.name,'var(--success)');
  };
  reader.onerror=function(){showNotif('❌ Gagal membaca file','var(--danger)');};
  reader.readAsDataURL(file);
}
function sbClearFile(){sbCurrentFile=null;document.getElementById('sb-file-info').style.display='none';document.getElementById('sb-drop-zone').style.display='';document.getElementById('sb-file-input').value='';}

function simpanSumberBelajar() {
  const judul=document.getElementById('sb-judul').value.trim();
  const paket=document.getElementById('sb-paket').value;
  if(!judul){showNotif('⚠️ Judul materi wajib diisi!','var(--warning)');return;}
  if(!paket){showNotif('⚠️ Pilih jenjang/paket!','var(--warning)');return;}
  // Check if file is still being read
  if(sbCurrentFile && !sbCurrentFile._base64){showNotif('⏳ File sedang diproses, tunggu sebentar...','var(--warning)');return;}
  const editId=document.getElementById('sb-edit-id').value;
  const fileExt=sbCurrentFile?sbCurrentFile.name.split('.').pop().toLowerCase():'';
  const fileIcon={pdf:'📄',doc:'📝',docx:'📝',ppt:'📊',pptx:'📊',jpg:'🖼️',jpeg:'🖼️',png:'🖼️'}[fileExt]||'📎';
  const uploaderRole=currentUser?currentUser.role:'admin';
  const uploaderId=currentUser?(uploaderRole==='guru'?currentUser.data.id:(uploaderRole==='siswa'?currentUser.data.id:'admin')):'admin';
  const item={
    id:editId||Date.now(),
    judul,paket,
    kelas:document.getElementById('sb-kelas').value,
    mapel:document.getElementById('sb-mapel').value.trim(),
    deskripsi:document.getElementById('sb-deskripsi').value.trim(),
    fileName:sbCurrentFile?sbCurrentFile.name:'',
    fileExt,fileIcon,
    fileData:sbCurrentFile?sbCurrentFile._base64:'',  // Store actual file as base64
    fileSize:sbCurrentFile?Math.round(sbCurrentFile.size/1024):0,
    url:document.getElementById('sb-url').value.trim(),
    uploadedBy:currentUser?currentUser.data.nama:'Admin',
    uploadedRole:uploaderRole,
    uploaderId:uploaderId,
    createdAt:editId?(state.sumber_belajar.find(x=>x.id==editId)?.createdAt||new Date().toISOString()):new Date().toISOString(),
    updatedAt:new Date().toISOString()
  };
  if(editId){const idx=state.sumber_belajar.findIndex(x=>x.id==editId);if(idx>=0)state.sumber_belajar[idx]=item;}else{state.sumber_belajar.unshift(item);}
  save();renderSumberBelajar();closeModal('modal-upload-sumber-belajar');sbClearFile();
  ['sb-judul','sb-mapel','sb-deskripsi','sb-url'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('sb-paket').value='';document.getElementById('sb-kelas').value='';document.getElementById('sb-edit-id').value='';
  showNotif('✅ Materi berhasil disimpan!');addActivity(`Materi sumber belajar: "${judul}" (${paket})`);
}

function renderSumberBelajar() {
  const filterPaket=document.getElementById('sb-filter-paket')?.value||'';
  const filterKelas=document.getElementById('sb-filter-kelas')?.value||'';
  const search=(document.getElementById('sb-search')?.value||'').toLowerCase();
  const role=currentUser?currentUser.role:'admin';
  const currentId=currentUser?(role==='guru'?currentUser.data.id:(role==='siswa'?currentUser.data.id:'admin')):'admin';

  let data=state.sumber_belajar.filter(sb=>{
    const mp=!filterPaket||sb.paket===filterPaket;
    const mk=!filterKelas||sb.kelas===filterKelas;
    const ms=!search||sb.judul.toLowerCase().includes(search)||(sb.mapel||'').toLowerCase().includes(search);
    // Guru only sees their own uploads + admin uploads; Admin sees all
    const roleFilter = role==='admin' ? true :
      role==='guru' ? (sb.uploadedRole==='admin' || sb.uploaderId===currentId) : true;
    return mp&&mk&&ms&&roleFilter;
  });

  const container=document.getElementById('sumber-belajar-list');if(!container)return;
  if(data.length===0){
    container.innerHTML=`<div class="empty-state"><div class="empty-icon">📚</div><h4>Belum ada materi</h4><p>${role==='guru'?'Klik "Upload Materi" untuk menambahkan materi pembelajaran Anda':'Belum ada materi tersedia'}</p></div>`;
    return;
  }
  const canEdit=role==='admin'||(role==='guru');
  const pC={'Paket A':'#1d4ed8','Paket B':'#065f46','Paket C':'#7c3aed'};
  const pB={'Paket A':'#dbeafe','Paket B':'#d1fae5','Paket C':'#ede9fe'};
  const grouped={};data.forEach(sb=>{if(!grouped[sb.paket])grouped[sb.paket]=[];grouped[sb.paket].push(sb);});
  container.innerHTML=Object.entries(grouped).map(([paket,items])=>`
    <div style="margin-bottom:24px;">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;">
        <div style="background:${pB[paket]||'#f1f5f9'};color:${pC[paket]||'#475569'};padding:6px 16px;border-radius:20px;font-weight:800;font-size:14px;">📚 ${paket}</div>
        <span style="font-size:13px;color:var(--text-muted);">${items.length} materi</span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px;">
        ${items.map(sb=>{
          const isOwner=role==='admin'||(role==='guru'&&sb.uploaderId===currentId);
          const hasFile=!!(sb.fileData&&sb.fileData.length>100);
          const hasUrl=!!sb.url;
          return `
          <div class="card" style="border-left:4px solid ${pC[sb.paket]||'#475569'};">
            <div class="card-body" style="padding:16px;">
              <div style="display:flex;align-items:flex-start;gap:12px;margin-bottom:12px;">
                <div style="font-size:34px;">${sb.fileIcon||'📎'}</div>
                <div style="flex:1;min-width:0;">
                  <div style="font-weight:700;font-size:14px;margin-bottom:4px;">${sb.judul}</div>
                  <div style="display:flex;gap:5px;flex-wrap:wrap;">
                    <span style="background:${pB[sb.paket]||'#f1f5f9'};color:${pC[sb.paket]||'#475569'};padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600;">${sb.paket}</span>
                    ${sb.kelas?`<span style="background:#f1f5f9;color:#475569;padding:2px 8px;border-radius:10px;font-size:11px;">${sb.kelas}</span>`:''}
                    ${sb.mapel?`<span style="background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:10px;font-size:11px;">${sb.mapel}</span>`:''}
                  </div>
                </div>
              </div>
              ${sb.deskripsi?`<p style="font-size:12.5px;color:var(--text-muted);margin-bottom:8px;">${sb.deskripsi}</p>`:''}
              <div style="font-size:11px;color:var(--text-muted);margin-bottom:4px;">📅 ${new Date(sb.createdAt).toLocaleDateString('id-ID')} · 👤 ${sb.uploadedBy||'-'}</div>
              ${sb.fileName?`<div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;">📄 ${sb.fileName}${sb.fileSize?' ('+sb.fileSize+' KB)':''} ${hasFile?'<span style="color:var(--success);font-weight:700;">✓ Siap unduh</span>':'<span style="color:var(--warning);">⚠ File tidak tersedia</span>'}</div>`:''}
              <div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:10px;">
                ${hasFile?`<button class="btn btn-sm btn-primary" style="font-size:12px;" onclick="unduhMateri('${sb.id}')">⬇️ Unduh File</button>`:''}
                ${hasUrl?`<a href="${sb.url}" target="_blank" class="btn btn-sm btn-outline" style="font-size:12px;">🔗 Buka Link</a>`:''}
                ${!hasFile&&!hasUrl?`<span style="font-size:12px;color:var(--text-muted);padding:5px 0;">Belum ada file</span>`:''}
                ${canEdit&&isOwner?`<button class="btn btn-sm btn-outline" style="font-size:12px;" onclick="editSumberBelajar('${sb.id}')">✏️</button><button class="btn btn-sm" style="font-size:12px;background:#fee2e2;color:#991b1b;border:none;border-radius:8px;padding:5px 10px;cursor:pointer;" onclick="hapusSumberBelajar('${sb.id}')">🗑️</button>`:''}
                ${canEdit&&role==='admin'&&sb.uploadedRole!=='admin'?`<button class="btn btn-sm" style="font-size:12px;background:#fee2e2;color:#991b1b;border:none;border-radius:8px;padding:5px 10px;cursor:pointer;" onclick="hapusSumberBelajar('${sb.id}')">🗑️</button>`:''}
              </div>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>`).join('');
}

function editSumberBelajar(id){const sb=state.sumber_belajar.find(x=>x.id==id);if(!sb)return;document.getElementById('sb-edit-id').value=sb.id;document.getElementById('sb-judul').value=sb.judul;document.getElementById('sb-paket').value=sb.paket;document.getElementById('sb-kelas').value=sb.kelas||'';document.getElementById('sb-mapel').value=sb.mapel||'';document.getElementById('sb-deskripsi').value=sb.deskripsi||'';document.getElementById('sb-url').value=sb.url||'';sbClearFile();openModal('modal-upload-sumber-belajar');}
function hapusSumberBelajar(id){const sb=state.sumber_belajar.find(x=>x.id==id);if(!sb||!confirm(`Hapus materi "${sb.judul}"?`))return;state.sumber_belajar=state.sumber_belajar.filter(x=>x.id!=id);save();renderSumberBelajar();showNotif('🗑️ Materi dihapus','var(--danger)');}
function unduhMateri(id){
  const sb=state.sumber_belajar.find(x=>x.id==id);
  if(!sb)return;
  if(sb.fileData){
    try{
      const a=document.createElement('a');
      a.href=sb.fileData;
      a.download=sb.fileName||('materi_'+sb.id+(sb.fileExt?'.'+sb.fileExt:''));
      document.body.appendChild(a);a.click();document.body.removeChild(a);
      showNotif('⬇️ Mengunduh: '+sb.fileName,'var(--success)');
    }catch(e){showNotif('❌ Gagal mengunduh file','var(--danger)');}
  } else if(sb.url){
    window.open(sb.url,'_blank');
    showNotif('🔗 Membuka tautan materi','var(--primary)');
  } else {
    showNotif('⚠️ File tidak tersedia','var(--danger)');
  }
}

