let paCurrentFile=null;
function paDragOver(e){e.preventDefault();document.getElementById('pa-drop-zone').style.borderColor='#4338ca';}
function paDragLeave(e){document.getElementById('pa-drop-zone').style.borderColor='#a5b4fc';}
function paDrop(e){e.preventDefault();paDragLeave(e);const f=e.dataTransfer.files[0];if(f)paProcessFile(f);}
function paHandleFile(e){const f=e.target.files[0];if(f)paProcessFile(f);}
function paProcessFile(file){const ext=file.name.split('.').pop().toLowerCase();if(!['pdf','doc','docx','ppt','pptx'].includes(ext)){showNotif('⚠️ Format: PDF, Word, PPT','var(--warning)');return;}if(file.size>10*1024*1024){showNotif('⚠️ Maks 10MB!','var(--warning)');return;}paCurrentFile=file;document.getElementById('pa-file-info').style.display='';document.getElementById('pa-file-name').textContent='📁 '+file.name;document.getElementById('pa-drop-zone').style.display='none';}
function paClearFile(){paCurrentFile=null;document.getElementById('pa-file-info').style.display='none';document.getElementById('pa-drop-zone').style.display='';document.getElementById('pa-file-input').value='';}

function simpanPerangkatAjar(){
  const nama=document.getElementById('pa-nama').value.trim();const jenis=document.getElementById('pa-jenis').value;
  if(!nama){showNotif('⚠️ Nama wajib diisi!','var(--warning)');return;}if(!jenis){showNotif('⚠️ Pilih jenis!','var(--warning)');return;}
  const editId=document.getElementById('pa-edit-id').value;const fileExt=paCurrentFile?paCurrentFile.name.split('.').pop().toLowerCase():'';const fileIcon={pdf:'📄',doc:'📝',docx:'📝',ppt:'📊',pptx:'📊'}[fileExt]||'📁';
  const item={id:editId||Date.now(),nama,jenis,mapel:document.getElementById('pa-mapel').value.trim(),kelas:document.getElementById('pa-kelas').value.trim(),deskripsi:document.getElementById('pa-deskripsi').value.trim(),fileName:paCurrentFile?paCurrentFile.name:'',fileExt,fileIcon,uploadedBy:currentUser?currentUser.data.nama:'Admin',uploadedRole:currentUser?currentUser.role:'admin',createdAt:editId?(state.perangkat_ajar.find(x=>x.id==editId)?.createdAt||new Date().toISOString()):new Date().toISOString(),updatedAt:new Date().toISOString()};
  if(editId){const idx=state.perangkat_ajar.findIndex(x=>x.id==editId);if(idx>=0)state.perangkat_ajar[idx]=item;}else{state.perangkat_ajar.unshift(item);}
  save();renderPerangkatAjar();closeModal('modal-upload-perangkat-ajar');paClearFile();
  ['pa-nama','pa-mapel','pa-kelas','pa-deskripsi'].forEach(id=>document.getElementById(id).value='');document.getElementById('pa-jenis').value='';document.getElementById('pa-edit-id').value='';
  showNotif('✅ Perangkat ajar disimpan!');addActivity(`Perangkat ajar: "${nama}" (${jenis})`);
  if(document.getElementById('gtk-stat-perangkat'))document.getElementById('gtk-stat-perangkat').textContent=state.perangkat_ajar.length;
}

function renderPerangkatAjar(){
  const search=(document.getElementById('pa-search')?.value||'').toLowerCase();const filterJenis=document.getElementById('pa-filter-jenis')?.value||'';
  let data=state.perangkat_ajar.filter(pa=>(!filterJenis||pa.jenis===filterJenis)&&(!search||pa.nama.toLowerCase().includes(search)||(pa.mapel||'').toLowerCase().includes(search)));
  const container=document.getElementById('perangkat-ajar-list');if(!container)return;
  if(data.length===0){container.innerHTML=`<div class="empty-state"><div class="empty-icon">📁</div><h4>Belum ada perangkat ajar</h4><p>Upload modul, RPP, silabus, dan dokumen pembelajaran</p></div>`;return;}
  const jC={RPP:'#1d4ed8',Silabus:'#065f46','Modul Ajar':'#7c3aed',ATP:'#92400e',LKPD:'#991b1b','Media Ajar':'#0369a1',Lainnya:'#475569'};
  container.innerHTML=`<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:14px;">`+data.map(pa=>`
    <div class="card" style="border-left:4px solid ${jC[pa.jenis]||'#475569'};">
      <div class="card-body" style="padding:16px;">
        <div style="display:flex;gap:10px;margin-bottom:10px;">
          <div style="font-size:32px;">${pa.fileIcon||'📁'}</div>
          <div style="flex:1;">
            <div style="font-weight:700;font-size:14px;margin-bottom:4px;">${pa.nama}</div>
            <div style="display:flex;gap:5px;flex-wrap:wrap;">
              <span style="background:${jC[pa.jenis]||'#475569'}22;color:${jC[pa.jenis]||'#475569'};padding:2px 8px;border-radius:10px;font-size:11.5px;font-weight:700;">${pa.jenis}</span>
              ${pa.mapel?`<span style="background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:10px;font-size:11px;">${pa.mapel}</span>`:''}
              ${pa.kelas?`<span style="background:#f1f5f9;color:#475569;padding:2px 8px;border-radius:10px;font-size:11px;">${pa.kelas}</span>`:''}
            </div>
          </div>
        </div>
        ${pa.deskripsi?`<p style="font-size:12.5px;color:var(--text-muted);margin-bottom:8px;">${pa.deskripsi}</p>`:''}
        <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">📅 ${new Date(pa.createdAt).toLocaleDateString('id-ID')} · ${pa.uploadedBy||'-'}${pa.fileName?`<br>📄 ${pa.fileName}`:''}</div>
        <div style="display:flex;gap:6px;">
          <button class="btn btn-sm btn-outline" style="font-size:12px;" onclick="editPerangkatAjar('${pa.id}')">✏️ Edit</button>
          <button class="btn btn-sm" style="font-size:12px;background:#fee2e2;color:#991b1b;border:none;border-radius:8px;padding:5px 10px;cursor:pointer;" onclick="hapusPerangkatAjar('${pa.id}')">🗑️ Hapus</button>
        </div>
      </div>
    </div>`).join('')+`</div>`;
}

function editPerangkatAjar(id){const pa=state.perangkat_ajar.find(x=>x.id==id);if(!pa)return;document.getElementById('pa-edit-id').value=pa.id;document.getElementById('pa-nama').value=pa.nama;document.getElementById('pa-jenis').value=pa.jenis;document.getElementById('pa-mapel').value=pa.mapel||'';document.getElementById('pa-kelas').value=pa.kelas||'';document.getElementById('pa-deskripsi').value=pa.deskripsi||'';paClearFile();openModal('modal-upload-perangkat-ajar');}
function hapusPerangkatAjar(id){const pa=state.perangkat_ajar.find(x=>x.id==id);if(!pa||!confirm(`Hapus "${pa.nama}"?`))return;state.perangkat_ajar=state.perangkat_ajar.filter(x=>x.id!=id);save();renderPerangkatAjar();showNotif('🗑️ Dihapus','var(--danger)');if(document.getElementById('gtk-stat-perangkat'))document.getElementById('gtk-stat-perangkat').textContent=state.perangkat_ajar.length;}

// ===================================================================
// ============= VIDEO PEMBELAJARAN ==================================
// ===================================================================

function simpanVideo(){
  const judul=document.getElementById('vp-judul').value.trim();const url=document.getElementById('vp-url').value.trim();
  if(!judul){showNotif('⚠️ Judul video wajib diisi!','var(--warning)');return;}if(!url){showNotif('⚠️ URL video wajib diisi!','var(--warning)');return;}
  const editId=document.getElementById('vp-edit-id').value;
  const item={id:editId||Date.now(),judul,url,paket:document.getElementById('vp-paket').value,kelas:document.getElementById('vp-kelas').value,mapel:document.getElementById('vp-mapel').value.trim(),deskripsi:document.getElementById('vp-deskripsi').value.trim(),thumbnail:document.getElementById('vp-thumbnail').value.trim(),showSiswa:document.getElementById('vp-show-siswa').checked,uploadedBy:currentUser?currentUser.data.nama:'Admin',uploadedRole:currentUser?currentUser.role:'admin',createdAt:editId?(state.video_pembelajaran.find(x=>x.id==editId)?.createdAt||new Date().toISOString()):new Date().toISOString(),updatedAt:new Date().toISOString()};
  if(editId){const idx=state.video_pembelajaran.findIndex(x=>x.id==editId);if(idx>=0)state.video_pembelajaran[idx]=item;}else{state.video_pembelajaran.unshift(item);}
  save();renderVideoPembelajaran();closeModal('modal-upload-video');
  ['vp-judul','vp-url','vp-mapel','vp-deskripsi','vp-thumbnail'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('vp-paket').value='';document.getElementById('vp-kelas').value='';document.getElementById('vp-show-siswa').checked=true;document.getElementById('vp-edit-id').value='';
  showNotif('✅ Video disimpan!');addActivity(`Video pembelajaran: "${judul}"`);
  if(document.getElementById('gtk-stat-video'))document.getElementById('gtk-stat-video').textContent=state.video_pembelajaran.length;
}

function getYoutubeId(url){const m=url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&?#]+)/);return m?m[1]:null;}

function renderVideoPembelajaran(){
  const search=(document.getElementById('vp-search')?.value||'').toLowerCase();const filterPaket=document.getElementById('vp-filter-paket')?.value||'';
  const role=currentUser?currentUser.role:'admin';const isSiswa=role==='siswa';
  let data=state.video_pembelajaran.filter(vp=>(!filterPaket||vp.paket===filterPaket)&&(!search||vp.judul.toLowerCase().includes(search)||(vp.mapel||'').toLowerCase().includes(search))&&(!isSiswa||vp.showSiswa));
  const container=document.getElementById('video-pembelajaran-list');if(!container)return;
  if(data.length===0){container.innerHTML=`<div class="empty-state"><div class="empty-icon">🎬</div><h4>Belum ada video pembelajaran</h4><p>${isSiswa?'Guru belum menambahkan video':'Upload video pembelajaran'}</p></div>`;return;}
  const canEdit=!isSiswa;
  container.innerHTML=`<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:16px;">`+data.map(vp=>{
    const ytId=getYoutubeId(vp.url);const thumb=vp.thumbnail||(ytId?`https://img.youtube.com/vi/${ytId}/mqdefault.jpg`:'');
    return `<div class="card" style="overflow:hidden;">
      <div style="width:100%;height:160px;background:#1e1b4b;position:relative;cursor:pointer;" onclick="previewVideo('${vp.id}')">
        ${thumb?`<img src="${thumb}" style="width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none'">`:``}
        <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.3);">
          <div style="width:52px;height:52px;background:rgba(220,38,38,0.9);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;">▶️</div>
        </div>
        ${vp.paket?`<div style="position:absolute;top:8px;left:8px;background:rgba(0,0,0,0.7);color:#fff;padding:3px 10px;border-radius:10px;font-size:11px;font-weight:700;">${vp.paket}${vp.kelas?' · '+vp.kelas:''}</div>`:''}
      </div>
      <div class="card-body" style="padding:14px;">
        <h4 style="font-size:14px;font-weight:800;margin-bottom:6px;">${vp.judul}</h4>
        <div style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:8px;">
          ${vp.mapel?`<span style="background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:10px;font-size:11px;">${vp.mapel}</span>`:''}
          ${vp.showSiswa?'<span style="background:#d1fae5;color:#065f46;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600;">👨‍🎓 Siswa</span>':'<span style="background:#f1f5f9;color:#475569;padding:2px 8px;border-radius:10px;font-size:11px;">Guru Saja</span>'}
        </div>
        ${vp.deskripsi?`<p style="font-size:12px;color:var(--text-muted);margin-bottom:8px;">${vp.deskripsi}</p>`:''}
        <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">📅 ${new Date(vp.createdAt).toLocaleDateString('id-ID')} · ${vp.uploadedBy||'-'}</div>
        <div style="display:flex;gap:6px;flex-wrap:wrap;">
          <button class="btn btn-sm btn-primary" style="font-size:12px;" onclick="previewVideo('${vp.id}')">▶️ Tonton</button>
          <a href="${vp.url}" target="_blank" class="btn btn-sm btn-outline" style="font-size:12px;">🔗 Link</a>
          ${canEdit?`<button class="btn btn-sm btn-outline" style="font-size:12px;" onclick="editVideo('${vp.id}')">✏️</button><button class="btn btn-sm" style="font-size:12px;background:#fee2e2;color:#991b1b;border:none;border-radius:8px;padding:5px 10px;cursor:pointer;" onclick="hapusVideo('${vp.id}')">🗑️</button>`:''}
        </div>
      </div>
    </div>`;
  }).join('')+`</div>`;
}

function previewVideo(id){const vp=state.video_pembelajaran.find(x=>x.id==id);if(!vp)return;document.getElementById('preview-video-title').textContent='🎬 '+vp.judul;document.getElementById('preview-video-info').textContent=(vp.paket||'')+(vp.kelas?' · '+vp.kelas:'')+(vp.mapel?' · '+vp.mapel:'');const ytId=getYoutubeId(vp.url);const embedEl=document.getElementById('preview-video-embed');if(ytId){embedEl.innerHTML=`<iframe width="100%" height="360" src="https://www.youtube.com/embed/${ytId}?autoplay=1" frameborder="0" allowfullscreen allow="autoplay" style="border-radius:0 0 18px 18px;"></iframe>`;}else{embedEl.innerHTML=`<div style="text-align:center;padding:60px;color:#fff;"><div style="font-size:56px;margin-bottom:16px;">🎬</div><p style="margin-bottom:16px;">${vp.judul}</p><a href="${vp.url}" target="_blank" class="btn btn-primary btn-lg">▶️ Buka Video</a></div>`;}openModal('modal-preview-video');}
function editVideo(id){const vp=state.video_pembelajaran.find(x=>x.id==id);if(!vp)return;document.getElementById('vp-edit-id').value=vp.id;document.getElementById('vp-judul').value=vp.judul;document.getElementById('vp-url').value=vp.url;document.getElementById('vp-paket').value=vp.paket||'';document.getElementById('vp-kelas').value=vp.kelas||'';document.getElementById('vp-mapel').value=vp.mapel||'';document.getElementById('vp-deskripsi').value=vp.deskripsi||'';document.getElementById('vp-thumbnail').value=vp.thumbnail||'';document.getElementById('vp-show-siswa').checked=!!vp.showSiswa;openModal('modal-upload-video');}
function hapusVideo(id){const vp=state.video_pembelajaran.find(x=>x.id==id);if(!vp||!confirm(`Hapus "${vp.judul}"?`))return;state.video_pembelajaran=state.video_pembelajaran.filter(x=>x.id!=id);save();renderVideoPembelajaran();showNotif('🗑️ Video dihapus','var(--danger)');if(document.getElementById('gtk-stat-video'))document.getElementById('gtk-stat-video').textContent=state.video_pembelajaran.length;}

