function showSubRuangMurid(sub){
  ['asesmen','sumber-belajar','kelasku'].forEach(s=>{const el=document.getElementById('sub-ruang-'+s);if(el)el.style.display=s===sub?'':'none';});
  const grid=document.querySelector('#page-ruang-murid .grid-3');if(grid)grid.style.display=sub?'none':'';
  if(sub==='asesmen')buildRuangMuridAsesmen();
  else if(sub==='sumber-belajar')buildSumberBelajarSiswa();
  else if(sub==='kelasku')buildKelasku();
}
function hideSubRuangMurid(){['asesmen','sumber-belajar','kelasku'].forEach(s=>{const el=document.getElementById('sub-ruang-'+s);if(el)el.style.display='none';});const grid=document.querySelector('#page-ruang-murid .grid-3');if(grid)grid.style.display='';}

function buildRuangMuridAsesmen(){
  const s=currentUser.data;const isK12=isKelas12(s.kelas||'');
  const jenisList=isK12?[{key:'PH',label:'Penilaian Harian',icon:'📝',color:'#0ea5e9'},{key:'PTS',label:'Penilaian Tengah Semester',icon:'📋',color:'#f59e0b'},{key:'PAS',label:'Penilaian Akhir Semester',icon:'📊',color:'#8b5cf6'},{key:'UPK',label:'Ujian Pendidikan Kesetaraan',icon:'🎓',color:'#10b981'}]:[{key:'PH',label:'Penilaian Harian',icon:'📝',color:'#0ea5e9'},{key:'PTS',label:'Penilaian Tengah Semester',icon:'📋',color:'#f59e0b'},{key:'PAS',label:'Penilaian Akhir Semester',icon:'📊',color:'#8b5cf6'}];
  document.getElementById('ruang-murid-asesmen-content').innerHTML=`<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:14px;">${jenisList.map(j=>`<div onclick="showAsesmenSiswa();setTimeout(()=>loadAsesmenByJenis('${j.key}'),100)" style="background:#fff;border-radius:14px;padding:22px 16px;text-align:center;cursor:pointer;border:2px solid var(--border);transition:.2s;" onmouseover="this.style.borderColor='${j.color}'" onmouseout="this.style.borderColor='var(--border)'"><div style="font-size:36px;margin-bottom:10px;">${j.icon}</div><div style="font-weight:800;font-size:15px;color:${j.color};margin-bottom:4px;">${j.key}</div><div style="font-size:12px;color:var(--text-muted);">${j.label}</div></div>`).join('')}</div>`;
}

function showSumberBelajarSiswa(){showPageRaw('ruang-murid');showSubRuangMurid('sumber-belajar');}
function showKelasku(){showPageRaw('ruang-murid');showSubRuangMurid('kelasku');}

function buildSumberBelajarSiswa(){
  const s=currentUser.data;const kelasNum=(s.kelas||'').match(/\d+/);const sKN=kelasNum?parseInt(kelasNum[0]):null;const paketSiswa=sKN?(sKN<=6?'Paket A':sKN<=9?'Paket B':'Paket C'):null;
  const materi=state.sumber_belajar.filter(sb=>!paketSiswa||!sb.paket||sb.paket===paketSiswa);
  const videos=state.video_pembelajaran.filter(v=>v.showSiswa&&(!paketSiswa||!v.paket||v.paket===paketSiswa));
  const container=document.getElementById('siswa-sumber-belajar-content');if(!container)return;
  if(materi.length===0&&videos.length===0){container.innerHTML=`<div class="empty-state"><div class="empty-icon">📚</div><h4>Belum ada materi</h4><p>Guru belum menambahkan materi untuk kelas Anda</p></div>`;return;}
  const pC={'Paket A':'#1d4ed8','Paket B':'#065f46','Paket C':'#7c3aed'};const pB={'Paket A':'#dbeafe','Paket B':'#d1fae5','Paket C':'#ede9fe'};
  const materiHtml=materi.length>0?`
    <h3 style="font-size:16px;font-weight:800;margin-bottom:14px;color:var(--primary);">📄 Materi Pembelajaran</h3>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px;margin-bottom:24px;">
      ${materi.map(sb=>{
        const hasFile=!!(sb.fileData&&sb.fileData.length>100);
        const hasUrl=!!sb.url;
        return `<div class="card" style="border-left:4px solid ${pC[sb.paket]||'#475569'};">
          <div class="card-body" style="padding:14px;">
            <div style="display:flex;gap:10px;align-items:flex-start;margin-bottom:10px;">
              <div style="font-size:28px;">${sb.fileIcon||'📎'}</div>
              <div>
                <div style="font-weight:700;font-size:13.5px;margin-bottom:4px;">${sb.judul}</div>
                <div style="display:flex;gap:4px;flex-wrap:wrap;">
                  ${sb.paket?`<span style="background:${pB[sb.paket]||'#f1f5f9'};color:${pC[sb.paket]||'#475569'};padding:1px 7px;border-radius:10px;font-size:10px;font-weight:700;">${sb.paket}</span>`:''}
                  ${sb.kelas?`<span style="background:#f1f5f9;color:#475569;padding:1px 7px;border-radius:10px;font-size:10px;">${sb.kelas}</span>`:''}
                  ${sb.mapel?`<span style="background:#fef3c7;color:#92400e;padding:1px 7px;border-radius:10px;font-size:10px;">${sb.mapel}</span>`:''}
                </div>
              </div>
            </div>
            ${sb.deskripsi?`<p style="font-size:12px;color:var(--text-muted);margin-bottom:6px;">${sb.deskripsi}</p>`:''}
            <div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;">👤 ${sb.uploadedBy||'-'} · 📅 ${new Date(sb.createdAt).toLocaleDateString('id-ID')}</div>
            ${sb.fileName?`<div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;">📄 ${sb.fileName}${sb.fileSize?' ('+sb.fileSize+' KB)':''}</div>`:''}
            <div style="display:flex;gap:6px;flex-wrap:wrap;">
              ${hasFile?`<button class="btn btn-sm btn-primary" style="font-size:12px;" onclick="unduhMateri('${sb.id}')">⬇️ Unduh File</button>`:''}
              ${hasUrl?`<a href="${sb.url}" target="_blank" class="btn btn-sm btn-outline" style="font-size:12px;">🔗 Buka Link</a>`:''}
              ${!hasFile&&!hasUrl?`<span style="font-size:12px;color:var(--text-muted);">Belum ada file</span>`:''}
            </div>
          </div>
        </div>`;
      }).join('')}
    </div>`:'';

  const videoHtml=videos.length>0?`
    <h3 style="font-size:16px;font-weight:800;margin-bottom:14px;color:#991b1b;">🎬 Video Pembelajaran</h3>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px;">
      ${videos.map(vp=>{const ytId=getYoutubeId(vp.url);const thumb=vp.thumbnail||(ytId?`https://img.youtube.com/vi/${ytId}/mqdefault.jpg`:'');return `<div class="card" style="overflow:hidden;cursor:pointer;" onclick="previewVideo('${vp.id}')"><div style="width:100%;height:140px;background:#1e1b4b;position:relative;">${thumb?`<img src="${thumb}" style="width:100%;height:100%;object-fit:cover;">`:`<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:48px;">🎬</div>`}<div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.3);"><div style="width:46px;height:46px;background:rgba(220,38,38,0.9);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;">▶️</div></div></div><div class="card-body" style="padding:12px;"><div style="font-weight:700;font-size:13px;">${vp.judul}</div>${vp.mapel?`<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">${vp.mapel}</div>`:''}</div></div>`;}).join('')}
    </div>`:'';

  container.innerHTML=materiHtml+videoHtml;
}

function buildKelasku(){
  const s=currentUser.data;const container=document.getElementById('siswa-kelasku-content');if(!container)return;
  const teman=state.siswa.filter(sx=>sx.kelas===s.kelas&&sx.id!==s.id&&sx.nisn!==s.nisn);
  const nilaiSiswa=state.nilai.filter(n=>n.siswaId===s.id||n.nisn===s.nisn);
  const byMapel={};nilaiSiswa.forEach(n=>{if(!byMapel[n.mapel])byMapel[n.mapel]=[];byMapel[n.mapel].push(n);});
  container.innerHTML=`<div class="grid-2" style="margin-bottom:20px;">
    <div class="card">
      <div class="card-header" style="background:linear-gradient(135deg,#065f46,#10b981);"><h3 style="color:#fff;">🏫 Info Kelas</h3></div>
      <div class="card-body">
        <div style="text-align:center;padding:16px 0;">
          <div style="font-size:56px;margin-bottom:12px;">🏫</div>
          <h2 style="font-size:24px;font-weight:900;color:var(--primary);">${s.kelas||'-'}</h2>
          <p style="color:var(--text-muted);margin-top:6px;">Kelas yang sedang Anda tempuh</p>
        </div>
        <div style="background:#f0fdf4;border-radius:10px;padding:14px;margin-top:10px;">
          <div style="display:grid;gap:8px;font-size:13.5px;">
            <div style="display:flex;justify-content:space-between;"><span style="color:var(--text-muted);">Nama</span><strong>${s.nama}</strong></div>
            <div style="display:flex;justify-content:space-between;"><span style="color:var(--text-muted);">NISN</span><strong>${s.nisn||'-'}</strong></div>
            <div style="display:flex;justify-content:space-between;"><span style="color:var(--text-muted);">Status</span><span class="badge ${s.status==='Aktif'?'badge-success':'badge-gray'}">${s.status||'Aktif'}</span></div>
          </div>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-header"><h3>👥 Teman Sekelas (${teman.length})</h3></div>
      <div class="card-body" style="padding:0;max-height:280px;overflow-y:auto;">
        ${teman.length===0?`<div style="padding:30px;text-align:center;color:var(--text-muted);">Belum ada teman sekelas</div>`:teman.map(t=>`<div style="display:flex;align-items:center;gap:12px;padding:12px 16px;border-bottom:1px solid #f1f5f9;"><div style="width:36px;height:36px;border-radius:50%;background:var(--primary);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;">${t.nama[0].toUpperCase()}</div><div><div style="font-weight:600;font-size:13.5px;">${t.nama}</div><div style="font-size:11px;color:var(--text-muted);">NISN: ${t.nisn||'-'}</div></div></div>`).join('')}
      </div>
    </div>
  </div>
  <div class="card">
    <div class="card-header"><h3>📚 Nilai Per Mata Pelajaran</h3></div>
    <div class="card-body" style="padding:0;">
      ${nilaiSiswa.length===0?`<div style="padding:20px;text-align:center;color:var(--text-muted);">📭 Belum ada nilai</div>`:
      `<table style="width:100%;border-collapse:collapse;font-size:13.5px;">
        <thead><tr style="background:#f8fafc;"><th style="padding:10px 14px;text-align:left;border-bottom:2px solid var(--border);">Mata Pelajaran</th><th style="padding:10px 14px;text-align:center;border-bottom:2px solid var(--border);">Rata-rata</th><th style="padding:10px 14px;text-align:center;border-bottom:2px solid var(--border);">Predikat</th></tr></thead>
        <tbody>${Object.entries(byMapel).map(([mapel,vals])=>{const avg=(vals.reduce((a,v)=>a+(parseFloat(v.nilai)||0),0)/vals.length).toFixed(1);const pred=parseFloat(avg)>=90?'A':parseFloat(avg)>=80?'B':parseFloat(avg)>=70?'C':'D';const c=parseFloat(avg)>=70?'var(--success)':parseFloat(avg)>=60?'var(--accent)':'var(--danger)';return `<tr><td style="padding:10px 14px;border-bottom:1px solid #f1f5f9;font-weight:600;">${mapel}</td><td style="padding:10px 14px;border-bottom:1px solid #f1f5f9;text-align:center;font-size:18px;font-weight:800;color:${c};">${avg}</td><td style="padding:10px 14px;border-bottom:1px solid #f1f5f9;text-align:center;"><span class="badge" style="background:${parseFloat(avg)>=70?'#d1fae5':'#fee2e2'};color:${parseFloat(avg)>=70?'#065f46':'#991b1b'};">${pred}</span></td></tr>`;}).join('')}</tbody>
      </table>`}
    </div>
  </div>`;
}

