function buildRuangGTK(){
  if(!currentUser)return;const g=currentUser.data;const role=currentUser.role;
  const soalGuru=role==='admin'?state.soal:state.soal.filter(s=>s.guruId===g.id||s.guruNama===g.nama);
  const ujianGuru=role==='admin'?state.ujian_online:state.ujian_online.filter(u=>u.guruId===g.id||u.guruNama===g.nama);
  if(document.getElementById('gtk-stat-soal'))document.getElementById('gtk-stat-soal').textContent=soalGuru.length;
  if(document.getElementById('gtk-stat-ujian'))document.getElementById('gtk-stat-ujian').textContent=ujianGuru.length;
  if(document.getElementById('gtk-stat-perangkat'))document.getElementById('gtk-stat-perangkat').textContent=state.perangkat_ajar.length;
  if(document.getElementById('gtk-stat-video'))document.getElementById('gtk-stat-video').textContent=state.video_pembelajaran.length;
}

// Override showPage to handle new pages
const _origShowPageV7=showPage;
showPage=function(id){
  if(id==='sumber-belajar'){const role=currentUser?currentUser.role:'admin';if(role==='siswa'){showSumberBelajarSiswa();return;}}
  _origShowPageV7(id);
  if(id==='sumber-belajar')setTimeout(renderSumberBelajar,50);
};

