// Initialize PKBM logo from saved setting on page load
(function() {
  const _savedLogoOnLoad = localStorage.getItem('pkbm_logo');
  const _loginLogoOnLoad = document.querySelector('.login-logo img');
  if (_savedLogoOnLoad && _loginLogoOnLoad) _loginLogoOnLoad.src = _savedLogoOnLoad;
})();

// ===== RESTORE SESSION SETELAH REFRESH =====
// Jika ada sesi tersimpan, masuk langsung tanpa harus login ulang
if (window._restoreSessionOnLoad && currentUser) {
  // Refresh data user dari state terkini (guru/siswa mungkin sudah diupdate)
  if (currentUser.role === 'guru') {
    const freshGuru = state.guru.find(g => g.id === currentUser.data.id);
    if (freshGuru) currentUser.data = freshGuru;
  } else if (currentUser.role === 'siswa') {
    const freshSiswa = state.siswa.find(s => s.nisn === currentUser.data.nisn);
    if (freshSiswa) currentUser.data = freshSiswa;
  }
  // Update session dengan data terbaru
  sessionStorage.setItem('pkbm_session', JSON.stringify(currentUser));
  enterApp();
}

