// =================== POINT 1: ADMIN BANK SOAL VIEW ================
// ===================================================================
function renderSoalAdmin() {
  const adminView = document.getElementById('bank-soal-admin-view');
  const guruView = document.getElementById('bank-soal-guru-view');
  if (!adminView || !guruView) return;

  if (!currentUser || currentUser.role !== 'admin') {
    adminView.style.display = 'none';
    guruView.style.display = '';
    return;
  }

  adminView.style.display = '';
  guruView.style.display = 'none';

  const byMapel = {};
  state.soal.forEach(s => {
    if (!byMapel[s.mapel]) byMapel[s.mapel] = [];
    byMapel[s.mapel].push(s);
  });

  const tbody = document.getElementById('tbody-soal-admin');
  if (!tbody) return;

  if (Object.keys(byMapel).length === 0) {
    tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;padding:40px;color:var(--text-muted);"><div style="font-size:36px;">📝</div>Belum ada soal</td></tr>`;
    return;
  }

  let idx = 1;
  tbody.innerHTML = Object.entries(byMapel).map(([mapel, soalList]) => {
    const tipes = [...new Set(soalList.map(s => s.tipe))].join(', ');
    const levels = [...new Set(soalList.map(s => s.level))].join(', ');
    const avgPoin = soalList.length ? (soalList.reduce((a, s) => a + (parseInt(s.poin) || 0), 0) / soalList.length).toFixed(0) : 0;
    return `<tr>
      <td>${idx++}</td>
      <td>
        <button onclick="bukaDetailSoalMapel(this.dataset.mapel)" data-mapel="${mapel.replace(/"/g,'&quot;')}"
          style="background:none;border:none;color:var(--primary);cursor:pointer;font-weight:700;font-size:14px;text-decoration:underline;text-align:left;padding:0;">
          📚 ${mapel}
        </button>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${soalList.length} soal</div>
      </td>
      <td style="font-size:12px;">${tipes}</td>
      <td style="font-size:12px;">${levels}</td>
      <td><strong>${avgPoin}</strong></td>
      <td>
        <button class="btn btn-sm btn-primary" onclick="bukaDetailSoalMapel(this.dataset.mapel)" data-mapel="${mapel.replace(/"/g,'&quot;')}" style="padding:4px 10px;font-size:11px;">👁️ Lihat Soal</button>
      </td>
    </tr>`;
  }).join('');
}

function bukaDetailSoalMapel(mapel) {
  const soalList = state.soal.filter(s => s.mapel === mapel);
  document.getElementById('modal-soal-mapel-title').textContent = `📚 Soal: ${mapel}`;
  document.getElementById('modal-soal-mapel-count').textContent = soalList.length;
  
  const levelColor = { Mudah:'badge-success', Sedang:'badge-warning', Sulit:'badge-danger' };
  const tbody = document.getElementById('tbody-soal-modal');
  if (soalList.length === 0) {
    tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;padding:30px;">Tidak ada soal</td></tr>`;
  } else {
    tbody.innerHTML = soalList.map((s, i) => `
      <tr>
        <td>${i+1}</td>
        <td style="max-width:280px;font-size:13px;">${s.pertanyaan.slice(0,100)}${s.pertanyaan.length>100?'...':''}</td>
        <td><span class="badge badge-primary" style="font-size:11px;">${s.tipe}</span></td>
        <td><span class="badge ${levelColor[s.level]||'badge-gray'}" style="font-size:11px;">${s.level}</span></td>
        <td><strong>${s.poin}</strong></td>
        <td>
          <button class="btn btn-sm" onclick="hapusSoalDariModal(${s.id}, this.dataset.mapel)" data-mapel="${mapel.replace(/"/g,'&quot;')}" style="padding:4px 8px;font-size:11px;background:#fee2e2;color:#991b1b;border:none;border-radius:6px;cursor:pointer;">🗑️ Hapus</button>
        </td>
      </tr>`).join('');
  }
  openModal('modal-soal-per-mapel');
}

function hapusSoalDariModal(id, mapel) {
  if (!confirm('Yakin hapus soal ini?')) return;
  state.soal = state.soal.filter(x => x.id !== id);
  save();
  renderSoalAdmin();
  bukaDetailSoalMapel(mapel);
  showNotif('🗑️ Soal dihapus!','var(--danger)');
}

// Override renderSoal to call renderSoalAdmin for admin
const _origRenderSoal = renderSoal;
renderSoal = function(list) {
  if (currentUser && currentUser.role === 'admin') {
    renderSoalAdmin();
  } else {
    _origRenderSoal(list);
  }
};

