state.naik_kelas = _loadState('naik_kelas', {});
const _origSave3 = save;
save = function() {
  _origSave3();
  localStorage.setItem('pkbm_naik_kelas', JSON.stringify(state.naik_kelas));
};

function getNaikKelasMapping() {
  return {
    'Paket A Kelas 1':'Paket A Kelas 2','Paket A Kelas 2':'Paket A Kelas 3','Paket A Kelas 3':'Paket A Kelas 4',
    'Paket A Kelas 4':'Paket A Kelas 5','Paket A Kelas 5':'Paket A Kelas 6','Paket A Kelas 6':'Paket B Kelas 7',
    'Paket B Kelas 7':'Paket B Kelas 8','Paket B Kelas 8':'Paket B Kelas 9','Paket B Kelas 9':'Paket C IPS Kelas 10',
    'Paket C IPS Kelas 10':'Paket C IPS Kelas 11','Paket C IPS Kelas 11':'Paket C IPS Kelas 12',
    'Paket A':'Paket B','Paket B':'Paket C',
    'X IPS 1':'XI IPS 1','X IPS 2':'XI IPS 2','X IPS 3':'XI IPS 3',
    'XI IPS 1':'XII IPS 1','XI IPS 2':'XII IPS 2','XI IPS 3':'XII IPS 3',
    'X IPA 1':'XI IPA 1','X IPA 2':'XI IPA 2',
    'XI IPA 1':'XII IPA 1','XI IPA 2':'XII IPA 2',
  };
}

function isKelasLulusan(kelas) {
  const k = (kelas||'').toLowerCase();
  return k.includes('xii') || k === 'kelas 12' || k.includes('paket c');
}

function populateNaikKelasFilter() {
  const sel = document.getElementById('nk-filter-kelas');
  if (!sel) return;
  const kelasList = [...new Set(state.siswa.map(s => s.kelas).filter(Boolean))].sort();
  sel.innerHTML = '<option value="">-- Pilih Kelas --</option>' + 
    kelasList.map(k => `<option>${k}</option>`).join('');
}

function loadNaikKelas() {
  const kelas = document.getElementById('nk-filter-kelas').value;
  if (!kelas) { showNotif('⚠️ Pilih kelas terlebih dahulu!','var(--warning)'); return; }
  const siswaKelas = state.siswa.filter(s => s.kelas === kelas);
  document.getElementById('nk-result').style.display = '';
  const isLulus = isKelasLulusan(kelas);
  const mapping = getNaikKelasMapping();
  const nextKelas = mapping[kelas] || (isLulus ? 'LULUS' : '?');
  document.getElementById('nk-title').textContent = `Siswa ${kelas} — ${siswaKelas.length} Siswa ${isLulus ? '(Kelas Kelulusan — Otomatis Lulus)' : ''}`;

  if (isLulus) {
    siswaKelas.forEach(s => { state.naik_kelas[s.id] = { status: 'Lulus', kelasBerikut: 'LULUS' }; });
    save();
  }

  const tbody = document.getElementById('tbody-naik-kelas');
  if (siswaKelas.length === 0) {
    tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;padding:30px;">Tidak ada siswa di kelas ini</td></tr>`;
    return;
  }

  tbody.innerHTML = siswaKelas.map((s, i) => {
    const nilaiSiswa = state.nilai.filter(n => n.siswaId === s.id);
    const avgNilai = nilaiSiswa.length ? (nilaiSiswa.reduce((a,n) => a+(parseFloat(n.nilai)||0), 0)/nilaiSiswa.length).toFixed(1) : '-';
    const nkData = state.naik_kelas[s.id];
    const currentStatus = nkData ? nkData.status : (isLulus ? 'Lulus' : '');
    
    return `<tr>
      <td>${isLulus ? '' : `<input type="checkbox" class="nk-check" data-id="${s.id}">`}</td>
      <td>${i+1}</td>
      <td><strong>${s.nama}</strong></td>
      <td style="font-size:12px;">${s.nisn||'-'}</td>
      <td><span class="badge badge-primary" style="font-size:11px;">${s.kelas||'-'}</span></td>
      <td style="font-weight:700;color:${avgNilai==='-'?'var(--text-muted)':parseFloat(avgNilai)>=70?'var(--success)':'var(--danger)'};">${avgNilai}</td>
      <td id="nk-status-cell-${s.id}">
        ${isLulus ? `<span class="badge badge-primary">🎓 Lulus Otomatis</span>` : `
        <select class="form-control" style="font-size:12px;padding:4px 8px;width:170px;" id="nk-sel-${s.id}" onchange="updateNaikKelasRow(${s.id}, this.value, '${nextKelas}', '${kelas}')">
          <option value="">-- Pilih --</option>
          <option value="Naik Kelas" ${currentStatus==='Naik Kelas'?'selected':''}>✅ Naik Kelas</option>
          <option value="Tidak Naik" ${currentStatus==='Tidak Naik'?'selected':''}>❌ Tidak Naik Kelas</option>
        </select>`}
      </td>
      <td style="font-weight:700;color:var(--primary);" id="nk-next-${s.id}">${isLulus?'🎓 LULUS':(currentStatus==='Naik Kelas'?nextKelas:currentStatus==='Tidak Naik'?kelas:'-')}</td>
    </tr>`;
  }).join('');
}

function updateNaikKelasRow(siswaId, status, nextKelas, currentKelas) {
  const el = document.getElementById('nk-next-' + siswaId);
  if (el) el.textContent = status === 'Naik Kelas' ? nextKelas : status === 'Tidak Naik' ? currentKelas : '-';
  if (!state.naik_kelas[siswaId]) state.naik_kelas[siswaId] = {};
  state.naik_kelas[siswaId].status = status;
  state.naik_kelas[siswaId].kelasBerikut = status === 'Naik Kelas' ? nextKelas : currentKelas;
}

function nkToggleAll(checked) {
  document.querySelectorAll('.nk-check').forEach(cb => cb.checked = checked);
}

function naikKelasSemuaTerpilih() {
  const kelas = document.getElementById('nk-filter-kelas').value;
  const mapping = getNaikKelasMapping();
  const nextKelas = mapping[kelas] || '?';
  const checks = document.querySelectorAll('.nk-check:checked');
  const targets = checks.length > 0 ? checks : document.querySelectorAll('.nk-check');
  targets.forEach(cb => {
    const id = parseInt(cb.dataset.id);
    const sel = document.getElementById('nk-sel-' + id);
    if (sel) { sel.value = 'Naik Kelas'; updateNaikKelasRow(id, 'Naik Kelas', nextKelas, kelas); }
  });
}

function tidakNaikKelasSemuaTerpilih() {
  const kelas = document.getElementById('nk-filter-kelas').value;
  const mapping = getNaikKelasMapping();
  const nextKelas = mapping[kelas] || '?';
  const checks = document.querySelectorAll('.nk-check:checked');
  const targets = checks.length > 0 ? checks : document.querySelectorAll('.nk-check');
  targets.forEach(cb => {
    const id = parseInt(cb.dataset.id);
    const sel = document.getElementById('nk-sel-' + id);
    if (sel) { sel.value = 'Tidak Naik'; updateNaikKelasRow(id, 'Tidak Naik', nextKelas, kelas); }
  });
}

function simpanNaikKelas() {
  const kelas = document.getElementById('nk-filter-kelas').value;
  const siswaKelas = state.siswa.filter(s => s.kelas === kelas);
  const isLulus = isKelasLulusan(kelas);
  let updated = 0;
  siswaKelas.forEach(s => {
    if (isLulus) {
      s.status = 'Lulus';
      state.naik_kelas[s.id] = { status: 'Lulus', kelasBerikut: 'LULUS' };
      updated++;
    } else {
      const nkData = state.naik_kelas[s.id];
      if (nkData && nkData.status === 'Naik Kelas' && nkData.kelasBerikut) {
        s.kelas = nkData.kelasBerikut;
        updated++;
      } else if (nkData && nkData.status === 'Tidak Naik') {
        updated++;
      }
    }
  });
  save(); renderSiswa();
  showNotif(`✅ ${updated} siswa berhasil diperbarui!`);
  addActivity(`Update naik kelas: ${updated} siswa dari ${kelas}`);
}

// Show naik kelas status in siswa portal
function getSiswaKelasStatus() {
  if (!currentUser || currentUser.role !== 'siswa') return null;
  const s = currentUser.data;
  return state.naik_kelas[s.id] || null;
}

