state.flayer_files = _loadState('flayer_files', {});
const _origSave4 = save;
save = function() {
  _origSave4();
  try { localStorage.setItem('pkbm_flayer_files', JSON.stringify(state.flayer_files || {})); } catch(e) {}
};

const _origRenderFiturExtraFields = renderFiturExtraFields;
renderFiturExtraFields = function(jenis) {
  if (jenis === 'flayer') {
    const container = document.getElementById('fb-extra-fields');
    if (!container) return;
    container.innerHTML = `
      <div class="form-group">
        <label class="form-label">Upload File (PDF, PNG, JPG) *</label>
        <div id="fb-flayer-dropzone" onclick="document.getElementById('fb-flayer-input').click()" 
          style="border:2.5px dashed var(--border);border-radius:12px;padding:28px;text-align:center;cursor:pointer;background:#fafbff;transition:.2s;">
          <div style="font-size:44px;margin-bottom:10px;">📄</div>
          <p style="font-weight:700;color:var(--primary);margin-bottom:4px;">Klik untuk upload file</p>
          <p style="font-size:12px;color:var(--text-muted);">Format: PDF, PNG, JPG · Maks 5MB</p>
          <input type="file" id="fb-flayer-input" accept=".pdf,.png,.jpg,.jpeg" style="display:none;" onchange="handleFlayerUpload(event)">
        </div>
        <div id="fb-flayer-preview" style="margin-top:10px;display:none;">
          <div id="fb-flayer-info" style="background:#d1fae5;border-radius:8px;padding:10px 14px;font-size:13px;font-weight:600;color:#065f46;">File terpilih</div>
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">Bisa Didownload Oleh</label>
        <div style="display:flex;gap:16px;margin-top:6px;">
          <label style="display:flex;align-items:center;gap:6px;cursor:pointer;"><input type="checkbox" id="fb-dl-guru" checked> 👨‍🏫 Guru</label>
          <label style="display:flex;align-items:center;gap:6px;cursor:pointer;"><input type="checkbox" id="fb-dl-siswa" checked> 👨‍🎓 Siswa</label>
        </div>
      </div>`;
  } else {
    _origRenderFiturExtraFields(jenis);
  }
};

window._currentFlayerData = null;
function handleFlayerUpload(event) {
  const file = event.target.files[0];
  if (!file) return;
  if (file.size > 5 * 1024 * 1024) { showNotif('⚠️ File terlalu besar! Maks 5MB.','var(--warning)'); return; }
  const allowed = ['application/pdf','image/png','image/jpeg','image/jpg'];
  if (!allowed.includes(file.type)) { showNotif('⚠️ Format tidak didukung! Gunakan PDF/PNG/JPG.','var(--warning)'); return; }
  const reader = new FileReader();
  reader.onload = function(e) {
    window._currentFlayerData = { name: file.name, type: file.type, data: e.target.result };
    document.getElementById('fb-flayer-preview').style.display = '';
    document.getElementById('fb-flayer-info').innerHTML = `✅ ${file.name} (${(file.size/1024).toFixed(1)} KB)`;
    document.getElementById('fb-flayer-dropzone').style.borderColor = 'var(--success)';
  };
  reader.readAsDataURL(file);
}

const _origSaveFiturBaru = saveFiturBaru;
saveFiturBaru = function() {
  const jenis = document.getElementById('fb-jenis').value;
  if (jenis !== 'flayer') { _origSaveFiturBaru(); return; }
  const judul = document.getElementById('fb-judul').value.trim();
  const deskripsi = document.getElementById('fb-deskripsi').value.trim();
  if (!judul) { showNotif('❌ Judul wajib diisi!','var(--danger)'); return; }
  const editId = document.getElementById('fb-edit-id').value;
  if (!editId && !window._currentFlayerData) { showNotif('❌ Upload file terlebih dahulu!','var(--danger)'); return; }
  const targetGuru = document.getElementById('fb-target-guru').checked;
  const targetSiswa = document.getElementById('fb-target-siswa').checked;
  const dlGuru = document.getElementById('fb-dl-guru')?.checked ?? true;
  const dlSiswa = document.getElementById('fb-dl-siswa')?.checked ?? true;
  const flayerId = editId || ('f' + Date.now());
  if (window._currentFlayerData) state.flayer_files[flayerId] = window._currentFlayerData;
  const fitur = {
    id: flayerId, judul, deskripsi, jenis:'flayer', ikon:'📄',
    targetGuru, targetSiswa,
    status: document.getElementById('fb-status').value,
    tglMulai: document.getElementById('fb-tgl-mulai').value,
    tglAkhir: document.getElementById('fb-tgl-akhir').value,
    prioritas: document.getElementById('fb-prioritas').value,
    extra: { dlGuru, dlSiswa, fileName: window._currentFlayerData ? window._currentFlayerData.name : '' },
    createdAt: new Date().toISOString(), updatedAt: new Date().toISOString()
  };
  if (editId) {
    const idx = state.fitur_baru.findIndex(f => f.id === editId);
    if (idx !== -1) state.fitur_baru[idx] = { ...state.fitur_baru[idx], ...fitur };
  } else {
    state.fitur_baru.unshift(fitur);
  }
  save(); window._currentFlayerData = null;
  closeModal('modal-buat-fitur'); renderFiturBaru(); renderFiturSidebar();
  showNotif('✅ Flayer/Surat berhasil diunggah & akan tampil di akun guru/siswa!');
  addActivity(`Admin upload flayer: ${judul}`);
};

const _origViewFiturForUser = viewFiturForUser;
viewFiturForUser = function(id) {
  const f = state.fitur_baru.find(x => x.id === id);
  if (!f || f.jenis !== 'flayer') { _origViewFiturForUser(id); return; }
  const flayerData = state.flayer_files[id];
  const role = currentUser ? currentUser.role : '';
  const canDownload = (role === 'guru' && f.extra?.dlGuru !== false) || (role === 'siswa' && f.extra?.dlSiswa !== false);
  document.getElementById('modal-view-fitur-title').textContent = `📄 ${f.judul}`;
  let previewHtml = '';
  if (flayerData) {
    if (flayerData.type === 'application/pdf') {
      previewHtml = `<embed src="${flayerData.data}" type="application/pdf" style="width:100%;height:420px;border-radius:8px;border:1px solid var(--border);">
        <p style="font-size:12px;color:var(--text-muted);margin-top:6px;text-align:center;">Jika PDF tidak tampil, klik Download.</p>`;
    } else {
      previewHtml = `<img src="${flayerData.data}" alt="${f.judul}" style="width:100%;max-height:460px;object-fit:contain;border-radius:8px;border:1px solid var(--border);">`;
    }
  } else {
    previewHtml = `<div style="text-align:center;padding:40px;color:var(--text-muted);">📄 File tidak tersedia</div>`;
  }
  document.getElementById('modal-view-fitur-body').innerHTML = `
    <p style="color:var(--text-muted);font-size:13.5px;margin-bottom:14px;">${f.deskripsi}</p>
    ${previewHtml}
    ${canDownload && flayerData ? `<div style="margin-top:14px;text-align:center;"><button onclick="downloadFlayerById('${id}')" class="btn btn-primary">⬇️ Download ${f.extra?.fileName||'File'}</button></div>` : ''}
    ${f.tglAkhir ? `<p style="font-size:11.5px;color:var(--text-muted);margin-top:10px;">📅 Berlaku hingga ${new Date(f.tglAkhir).toLocaleDateString('id-ID')}</p>` : ''}
  `;
  const actionBtn = document.getElementById('modal-view-fitur-action-btn');
  if (actionBtn) actionBtn.style.display = 'none';
  openModal('modal-view-fitur');
};

function downloadFlayerById(fiturId) {
  const flayerData = state.flayer_files[fiturId];
  if (!flayerData) { showNotif('⚠️ File tidak ditemukan!','var(--warning)'); return; }
  const a = document.createElement('a');
  a.href = flayerData.data; a.download = flayerData.name || 'flayer'; a.click();
  showNotif('✅ File sedang didownload!');
}

function showFlayerPopups() {
  const role = currentUser ? currentUser.role : '';
  if (role === 'admin') return;
  const now = new Date();
  const flayers = state.fitur_baru.filter(f => {
    if (f.jenis !== 'flayer' || f.status !== 'aktif') return false;
    if (f.tglMulai && new Date(f.tglMulai) > now) return false;
    if (f.tglAkhir && new Date(f.tglAkhir) < now) return false;
    return role === 'guru' ? f.targetGuru : f.targetSiswa;
  });
  if (flayers.length > 0) {
    setTimeout(() => {
      viewFiturForUser(flayers[0].id);
      if (flayers.length > 1) showNotif(`📢 Ada ${flayers.length} pengumuman/flayer baru!`);
    }, 1500);
  }
}

