// ===== LOGIN: Remember me =====
function handleRememberMe() {
  const checked = document.getElementById('remember-me').checked;
  if (!checked) {
    localStorage.removeItem('siaceng_saved_user');
  }
}

function loadRememberedLogin() {
  const saved = localStorage.getItem('siaceng_saved_user');
  if (saved) {
    try {
      const data = JSON.parse(saved);
      const userInput = document.getElementById('admin-user');
      const passInput = document.getElementById('admin-pass');
      const rememberCheck = document.getElementById('remember-me');
      if (userInput) userInput.value = data.u || '';
      if (passInput) passInput.value = data.p || '';
      if (rememberCheck) rememberCheck.checked = true;
    } catch(e) {}
  }
}

// Override doLogin to save credentials if remember-me is checked
const _origDoLogin = window.doLogin;
window.doLogin = function() {
  const remember = document.getElementById('remember-me');
  if (remember && remember.checked) {
    const u = document.getElementById('admin-user').value;
    const p = document.getElementById('admin-pass').value;
    localStorage.setItem('siaceng_saved_user', JSON.stringify({u, p}));
  }
  if (_origDoLogin) _origDoLogin();
};

// ===== LOGIN: Forgot password =====
function openForgotPassword() {
  openModal('modal-lupa-password');
  const res = document.getElementById('forgot-result');
  if (res) { res.style.display = 'none'; res.textContent = ''; }
}

function doForgotPassword() {
  const username = document.getElementById('forgot-username').value.trim();
  const res = document.getElementById('forgot-result');
  if (!username) { showNotif('⚠️ Masukkan username terlebih dahulu', 'var(--warning)'); return; }
  
  let found = null;
  let role = '';
  let info = '';
  
  // Check admin
  if (username === 'admin') {
    role = 'Admin';
    info = 'Password admin dikelola oleh pengelola sistem. Hubungi administrator untuk reset password.';
  } else {
    // Check guru
    const guru = state.guru.find(g => g.nama && g.nama.toLowerCase() === username.toLowerCase());
    if (guru) {
      role = 'Guru';
      const pw = formatTtlPassword(guru.ttl);
      info = `<strong>Username:</strong> ${guru.nama}<br><strong>Password:</strong> ${pw || 'Belum diatur (Tanggal lahir DDMMYYYY)'}<br><small>Tanggal lahir: ${guru.ttl || 'Belum diisi'}</small>`;
    } else {
      // Check siswa
      const siswa = state.siswa.find(s => s.nisn === username || (s.nama && s.nama.toLowerCase() === username.toLowerCase()));
      if (siswa) {
        role = 'Siswa';
        const pw = formatTtlPassword(siswa.ttl);
        info = `<strong>Username:</strong> ${siswa.nisn}<br><strong>Password:</strong> ${pw || siswa.nisn || 'Sama dengan NISN'}<br><small>Tanggal lahir: ${siswa.ttl || 'Belum diisi'}</small>`;
      }
    }
  }
  
  if (!role && username !== 'admin') {
    res.style.display = 'block';
    res.style.background = '#fee2e2';
    res.style.color = '#991b1b';
    res.innerHTML = '❌ Username tidak ditemukan dalam sistem.';
    return;
  }
  
  res.style.display = 'block';
  res.style.background = '#d1fae5';
  res.style.color = '#065f46';
  res.innerHTML = `✅ <strong>Akun ${role} Ditemukan</strong><br><br>${info}`;
}

