function saveEditPassSiswa() {
  const id = document.getElementById('edit-pass-siswa-id').value;
  const newPass = document.getElementById('edit-pass-siswa-value').value.trim();
  if (!newPass) { showNotif('⚠️ Password tidak boleh kosong', 'var(--warning)'); return; }
  const s = state.siswa.find(x => String(x.id) === String(id));
  if (!s) return;
  s.password = newPass;
  save();
  renderSiswa();
  closeModal('modal-edit-pass-siswa');
  showNotif(`✅ Password siswa ${s.nama} berhasil diubah!`);
}

